data["map_desc_0001"] = {  key = "map_desc_0001",  scn = "凌云剑宗山门遗址。妖族大军压境之日，全宗剑修燃尽修为，以身化道，终与敌偕亡。",  tcn = "凌雲劍宗山門遺址。妖族大軍壓境之日，全宗劍修燃盡修為，以身化道，終與敵偕亡。",  en = "The ruins of the Lingyun Sword Sect\'s mountain gate. On the day the demonic horde descended, every swordsman of the sect burned their cultivation to its limit, merging their beings with the Dao, ultimately perishing together with the enemy.",  ru = "Руины врат горы секты Меча Линъюнь. В день, когда армия демонических существ подступила к границам, все мечники секты сожгли свою культивацию, воплотив себя в Дао, и в конце пали вместе с врагом.",  jp = "凌雲剣宗の山門跡。妖族の大軍が迫り来るその日、宗門の剣修は全員、修為を燃やし尽くし、身をもって道と化し、ついには敵と共に滅び去った。",  kr = "영운검종의 산문 유적. 요족 대군이 장악하던 그날, 종문의 검수들은 모두 수행을 불살라, 몸으로 도를 이루어 마침내 적과 함께 소멸하였다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["map_desc_0002"] = {  key = "map_desc_0002",  scn = "万法玄宗圣地残破山门。末代宗主为护道统不坠，启上古禁制，如今山石纹理自显残缺功法，灵气驳杂混乱。",  tcn = "萬法玄宗聖地殘破山門。末代宗主為護道統不墜，啟上古禁制，如今山石紋理自顯殘缺功法，靈氣駁雜混亂。",  en = "The shattered mountain gate of the Sacred Land of the Wanfa Xuan Sect. To protect the sect\'s lineage from falling, its last patriarch activated an ancient forbidden seal. Now, the patterns in the stone naturally reveal fragmented techniques, and the spiritual energy is chaotic and impure.",  ru = "Разрушенные врата горы Святой земли секты Ваньфа Сюань. Чтобы защитить линию преемственности секты от падения, её последний патриарх активировал древнюю запретную печать. Теперь узоры на камнях естественным образом проявляют фрагментарные техники, а духовная энергия хаотична и нечиста.",  jp = "万法玄宗の聖地にある崩れかけの山門。末代宗主が道統の断絶を防ぐため、上古の禁制を発動した。今では岩肌の紋様自らが欠けた功法を現し、霊気が入り乱れ混濁している。",  kr = "만법현종의 성지에 있는 산문의 잔해. 말대 종주가 도통이 끊어지지 않도록 상고의 금제를 발동했다. 지금은 바위의 결에 스스로 불완전한 공법이 나타나며, 영기가 뒤섞여 혼란스럽다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["map_desc_0003"] = {  key = "map_desc_0003",  scn = "瀚海凌霄宗故地。决战关键时刻，潜伏的妖族内应突然引爆海底灵脉。宗主被迫逆转大阵，将失控的灵力与敌我一同封入九幽海眼，同沉深渊。",  tcn = "瀚海凌霄宗故地。決戰關鍵時刻，潛伏的妖族內應突然引爆海底靈脈。宗主被迫逆轉大陣，將失控的靈力與敵我一同封入九幽海眼，同沉深淵。",  en = "The former site of the Hanhai Lingxiao Sect. At the critical moment of the final battle, a hidden demonic spy suddenly detonated the undersea spirit vein. The sect patriarch was forced to reverse the grand formation, sealing the runaway spiritual power, friend and foe alike, into the Nine Nether Sea Eye, sinking together into the abyss.",  ru = "Бывшее место секты Ханьхай Линсяо. В решающий момент финальной битвы скрытый шпион демонических существ внезапно взорвал подводную духовную жилу. Патриарх секты был вынужден обратить великую формацию вспять, запечатав вышедшую из-под контроля духовную силу, друзей и врагов, в Око Девяти Бездн Моря, погрузив всех вместе в пучину.",  jp = "瀚海凌霄宗の旧地。決戦の瀬戸際に、潜伏していた妖族の内通者が突如、海底霊脈を爆破した。宗主はやむなく大陣を逆転させ、制御不能の霊力と敵味方を共に九幽の海淵へ封じ、共に深淵へと沈めた。",  kr = "한해능효종의 옛 터. 결전의 결정적 순간에 잠복해 있던 요족의 내응이 갑자기 해저 영맥을 폭발시켰다. 종주는 어쩔 수 없이 대진을 역전시켜, 제어 불가능한 영력과 적아를 함께 구유해안에 봉인하여 심연으로 가라앉혔다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["map_desc_0004"] = {  key = "map_desc_0004",  scn = "此处乃天机阁中枢。妖劫未至，高层已被大妖以隐秘血脉秘法侵蚀心智。中枢大阵从内部瓦解，万年天机阁于无声中倾覆，如今只余被万千残魂凝视的错觉。",  tcn = "此處乃天機閣中樞。妖劫未至，高層已被大妖以隱秘血脈秘法侵蝕心智。中樞大陣從內部瓦解，萬年天機閣於無聲中傾覆，如今只餘被萬千殘魂凝視的錯覺。",  en = "This was the core of the Tianji Pavilion. Before the demonic calamity even arrived, its upper echelons had already had their minds corrupted by a great demon using a secret bloodline technique. The core formation collapsed from within, and the ten-thousand-year-old Tianji Pavilion silently fell. Now, only the illusion of being watched by countless remnant souls remains.",  ru = "Здесь находилось ядро Павильона Тяньцзи. Ещё до наступления демонической катастрофы, высшие слои уже были развращены в уме великим демоном, использовавшим технику тайной кровной линии. Ядерная формация рухнула изнутри, и десятитысячелетний Павильон Тяньцзи пал в безмолвии. Теперь осталась лишь иллюзия, будто за тобой наблюдают бесчисленные остаточные души.",  jp = "ここは天機閣の中枢であった。妖劫が未だ到来せぬうちに、上層部はすでに大妖の秘匿された血脈秘法によって心神を侵蝕されていた。中枢の大陣が内側から瓦解し、万年の天機閣は音もなく崩壊した。今となっては、無数の残魂に見つめられているような錯覚だけが残っている。",  kr = "이곳은 천기각의 중추였다. 요겁이 닥치기 전, 고위층은 이미 대요의 은밀한 혈통 비법으로 심지가 침식당한 상태였다. 중추 대진이 내부에서 와해되며, 만년의 천기각은 소리 없이 무너졌다. 지금은 수많은 잔혼이 응시하는 착각만이 남아 있을 뿐이다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["map_desc_0005"] = {  key = "map_desc_0005",  scn = "此处为寒极宗最后驻地。覆灭之际，宗门已连斩妖圣，胜券在握。九天之外忽现巨爪，将千里山河一同永化冰冢。",  tcn = "此處為寒極宗最後駐地。覆滅之際，宗門已連斬妖聖，勝券在握。九天之外忽現巨爪，將千里山河一同永化冰冢。",  en = "This was the final stronghold of the Hanji Sect. At the moment of its destruction, the sect had already slain multiple demon saints, holding victory within its grasp. Suddenly, from beyond the Nine Heavens, a colossal claw appeared, eternally transforming a thousand miles of mountains and rivers into a frozen tomb.",  ru = "Это был последний оплот секты Ханьцзи. В момент её уничтожения, секта уже убила нескольких демонических святых, держа победу в своих руках. Внезапно, из-за пределов Девяти Небес, появился гигантский коготь, навеки превративший тысячу ли гор и рек в ледяную гробницу.",  jp = "ここは寒極宗の最後の拠点であった。壊滅のその時、宗門はすでに妖聖を続けて討ち取り、勝利を確信していた。九天の彼方から突如現れた巨爪が、千里の山河をも共に永遠の氷の墓標へと変えた。",  kr = "이곳은 한극종의 마지막 주둔지였다. 멸망할 당시, 종문은 이미 연이어 요성을 베며 승리를 손에 쥐고 있었다. 구천 밖에서 갑자기 나타난 거대한 손발톱이 천 리의 산하를 함께 영원한 얼음 무덤으로 만들었다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
