data["strategy_guide_desc_0001"] = {  key = "strategy_guide_desc_0001",  scn = "· 任务：Tab \n· 世界：F \n· 右键：穿戴/转移 \n· 左键：采集/详情/攻击/确定 \n· WASD键 或 ↑←↓→键：移动 \n· 1：洞府 \n· 2：角色 \n· 3：储物 \n· 4：道行 \n· 5：论道 \n· 6：宝阁",  tcn = "· 任務：Tab \n· 世界：F \n· 右鍵：穿戴/轉移 \n· 左鍵：採集/詳情/攻擊/確定 \n· WASD鍵 或 ↑←↓→鍵：移動 \n· 1：洞府 \n· 2：角色 \n· 3：儲物 \n· 4：道行 \n· 5：論道 \n· 6：寶閣",  en = "· Quests: Tab \n· World: F \n· Right-click: Equip/Transfer \n· Left-click: Gather/Details/Attack/Confirm \n· WASD keys or ↑←↓→ keys: Move \n· 1: Abode \n· 2: Character \n· 3: Storage \n· 4: Cultivation \n· 5: Dao Discussion \n· 6: Treasure Pavilion",  ru = "· Задания: Tab \n· Мир: F \n· ПКМ: Экипировать/Переместить \n· ЛКМ: Собрать/Подробности/Атаковать/Подтвердить \n· Клавиши WASD или ↑←↓→: Движение \n· 1: Обитель \n· 2: Персонаж \n· 3: Хранилище \n· 4: Культивация \n· 5: Беседа о Дао \n· 6: Сокровищница",  jp = "· クエスト：Tab \n· 世界：F \n· 右クリック：装備/移動 \n· 左クリック：採取/詳細/攻撃/決定 \n· WASDキー または ↑←↓→キー：移動 \n· 1：洞府 \n· 2：キャラクター \n· 3：所持品 \n· 4：道行き \n· 5：論道 \n· 6：宝閣",  kr = "· 퀘스트: Tab \n· 세계: F \n· 우클릭: 장착/이동 \n· 좌클릭: 채집/상세/공격/확인 \n· WASD 키 또는 ↑←↓→ 키: 이동 \n· 1: 동부 \n· 2: 캐릭터 \n· 3: 보관함 \n· 4: 도력 \n· 5: 논도 \n· 6: 보물 전당",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["strategy_guide_desc_0002"] = {  key = "strategy_guide_desc_0002",  scn = "道具品质分为下品（白）、中品（<color=#00DB00>绿</color>）、上品（<color=#00E3E3>蓝</color>）、极品（<color=#B15BFF>紫</color>）、天品（<color=#FFD306>金</color>）、道品（<color=#FF5809>红</color>），在凡界（沧澜界）<color=#9AFF02>最高</color>只能获得天品（<color=#FFD306>金</color>），<color=#9AFF02>飞升之后</color>才会获得道品（<color=#FF5809>红</color>）道具。",  tcn = "道具品質分為下品（白）、中品（<color=#00DB00>綠</color>）、上品（<color=#00E3E3>藍</color>）、極品（<color=#B15BFF>紫</color>）、天品（<color=#FFD306>金</color>）、道品（<color=#FF5809>紅</color>），在凡界（滄瀾界）<color=#9AFF02>最高</color>只能獲得天品（<color=#FFD306>金</color>），<color=#9AFF02>飛升之後</color>才會獲得道品（<color=#FF5809>紅</color>）道具。",  en = "Item quality is divided into Inferior (White), Medium (<color=#00DB00>Green</color>), Superior (<color=#00E3E3>Blue</color>), Supreme (<color=#B15BFF>Purple</color>), Heavenly (<color=#FFD306>Gold</color>), and Dao (<color=#FF5809>Red</color>). In the mortal realm (Canglan Realm), the <color=#9AFF02>highest</color> obtainable is Heavenly (<color=#FFD306>Gold</color>). Dao (<color=#FF5809>Red</color>) items can only be obtained <color=#9AFF02>after Ascension</color>.",  ru = "Качество предметов делится на: Низший (Белый), Средний (<color=#00DB00>Зелёный</color>), Высший (<color=#00E3E3>Синий</color>), Превосходный (<color=#B15BFF>Фиолетовый</color>), Небесный (<color=#FFD306>Золотой</color>), Дао (<color=#FF5809>Красный</color>). В мире смертных (Цанлань) <color=#9AFF02>максимальный</color> доступный уровень — Небесный (<color=#FFD306>Золотой</color>). Предметы уровня Дао (<color=#FF5809>Красный</color>) можно получить только <color=#9AFF02>после Вознесения</color>.",  jp = "アイテムの品質は下品（白）、中品（<color=#00DB00>緑</color>）、上品（<color=#00E3E3>青</color>）、極品（<color=#B15BFF>紫</color>）、天品（<color=#FFD306>金</color>）、道品（<color=#FF5809>赤</color>）に分かれる。凡界（滄瀾界）では<color=#9AFF02>最高</color>で天品（<color=#FFD306>金</color>）までしか入手できず、<color=#9AFF02>飛昇後</color>に道品（<color=#FF5809>赤</color>）が入手可能となる。",  kr = "아이템 품질은 하품(흰색), 중품(<color=#00DB00>초록</color>), 상품(<color=#00E3E3>파랑</color>), 극품(<color=#B15BFF>보라</color>), 천품(<color=#FFD306>금색</color>), 도품(<color=#FF5809>빨강</color>)으로 구분됩니다. 범계(창란계)에서는 <color=#9AFF02>최고</color> 천품(<color=#FFD306>금색</color>)까지 획득 가능하며, <color=#9AFF02>비승 이후</color> 도품(<color=#FF5809>빨강</color>) 아이템을 획득할 수 있습니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["strategy_guide_desc_0003"] = {  key = "strategy_guide_desc_0003",  scn = "在关卡战斗中，角色会<color=#9AFF02>自动移动、战斗、服药和采集</color>，可<color=#9AFF02>长期挂机</color>，关卡不会结束。\n· 玩家也可用<color=#9AFF02>WASD键位</color>控制角色移动，或用<color=#9AFF02>鼠标点击</color>灵药、灵材、灵矿进行采集，也可攻击怪物。\n· 当<color=#9AFF02>气血</color>和<color=#9AFF02>真元</color>较低时，会自动服用背包中的<color=#9AFF02>气血丹</color>和<color=#9AFF02>真元丹</color>；点击血条/蓝条旁的<color=#9AFF02>小葫芦图标</color>，可设置服药<color=#9AFF02>比例</color>。\n· <color=#9AFF02>无气血丹时</color>，角色死亡会在一定时间后<color=#9AFF02>复活</color>；<color=#9AFF02>无真元丹时</color>，角色只会释放<color=#9AFF02>普攻</color>。",  tcn = "在關卡戰鬥中，角色會<color=#9AFF02>自動移動、戰鬥、服藥和採集</color>，可<color=#9AFF02>長期掛機</color>，關卡不會結束。\n· 玩家也可用<color=#9AFF02>WASD鍵位</color>控制角色移動，或用<color=#9AFF02>滑鼠點擊</color>靈藥、靈材、靈礦進行採集，也可攻擊怪物。\n· 當<color=#9AFF02>氣血</color>和<color=#9AFF02>真元</color>較低時，會自動服用背包中的<color=#9AFF02>氣血丹</color>和<color=#9AFF02>真元丹</color>；點擊血條/藍條旁的<color=#9AFF02>小葫蘆圖示</color>，可設置服藥<color=#9AFF02>比例</color>。\n· <color=#9AFF02>無氣血丹時</color>，角色死亡會在一定時間後<color=#9AFF02>復活</color>；<color=#9AFF02>無真元丹時</color>，角色只會釋放<color=#9AFF02>普攻</color>。",  en = "During stage combat, the character will <color=#9AFF02>automatically move, fight, take pills, and gather</color>. You can <color=#9AFF02>leave it idle for a long time</color>, and the stage will not end.\n· Players can also use the <color=#9AFF02>WASD keys</color> to control character movement, or <color=#9AFF02>click with the mouse</color> on spirit herbs, spirit materials, and spirit ores to gather them, as well as attack monsters.\n· When <color=#9AFF02>Health</color> and <color=#9AFF02>True Energy</color> are low, pills from the backpack will be used automatically. Click the <color=#9AFF02>small gourd icon</color> next to the health/mana bar to set the <color=#9AFF02>usage threshold</color>.\n· <color=#9AFF02>Without Health pills</color>, the character will <color=#9AFF02>revive</color> after a certain time upon death; <color=#9AFF02>without True Energy pills</color>, the character will only use <color=#9AFF02>basic attacks</color>.",  ru = "Во время боя на этапе персонаж будет <color=#9AFF02>автоматически перемещаться, сражаться, принимать пилюли и собирать ресурсы</color>. Можно <color=#9AFF02>оставить надолго</color>, этап не закончится.\n· Игрок также может использовать <color=#9AFF02>клавиши WASD</color> для управления движением персонажа или <color=#9AFF02>щелчком мыши</color> собирать духовные травы, материалы и руды, а также атаковать монстров.\n· Когда <color=#9AFF02>Ци и Кровь</color> и <color=#9AFF02>Истинная энергия</color> становятся низкими, автоматически используются пилюли из рюкзака. Нажмите <color=#9AFF02>иконку маленькой тыквы</color> рядом с полосками здоровья/маны, чтобы установить <color=#9AFF02>порог использования</color>.\n· <color=#9AFF02>Без пилюль здоровья</color> персонаж <color=#9AFF02>возродится</color> через некоторое время после смерти; <color=#9AFF02>без пилюль истинной энергии</color> персонаж будет использовать только <color=#9AFF02>обычные атаки</color>.",  jp = "ステージ戦闘では、キャラクターは<color=#9AFF02>自動的に移動、戦闘、服薬、採取</color>を行い、<color=#9AFF02>長時間放置</color>が可能で、ステージは終了しません。\n· プレイヤーは<color=#9AFF02>WASDキー</color>でキャラクターを移動させるか、<color=#9AFF02>マウスクリック</color>で霊薬、霊材、霊鉱を採取したり、モンスターを攻撃したりすることもできます。\n· <color=#9AFF02>気血</color>と<color=#9AFF02>真元</color>が少なくなると、バックパック内の<color=#9AFF02>気血丹</color>と<color=#9AFF02>真元丹</color>を自動的に服用します。HP/MPゲージ横の<color=#9AFF02>小さな瓢箪アイコン</color>をクリックすると、服薬<color=#9AFF02>割合</color>を設定できます。\n· <color=#9AFF02>気血丹がない場合</color>、キャラクターが死亡すると一定時間後に<color=#9AFF02>復活</color>します。<color=#9AFF02>真元丹がない場合</color>、キャラクターは<color=#9AFF02>通常攻撃</color>のみを行います。",  kr = "스테이지 전투에서 캐릭터는 <color=#9AFF02>자동으로 이동, 전투, 복약, 채집</color>을 수행합니다. <color=#9AFF02>장시간 방치</color>가 가능하며, 스테이지는 종료되지 않습니다.\n· 플레이어는 <color=#9AFF02>WASD 키</color>로 캐릭터를 이동시키거나, <color=#9AFF02>마우스 클릭</color>으로 영약, 영재, 영광을 채집하고 몬스터를 공격할 수도 있습니다.\n· <color=#9AFF02>기혈</color>과 <color=#9AFF02>진원</color>이 낮아지면 인벤토리의 <color=#9AFF02>기혈단</color>과 <color=#9AFF02>진원단</color>을 자동으로 복용합니다. HP/MP 게이지 옆의 <color=#9AFF02>작은 호리병박 아이콘</color>을 클릭하여 복약 <color=#9AFF02>비율</color>을 설정할 수 있습니다.\n· <color=#9AFF02>기혈단이 없을 때</color> 캐릭터가 사망하면 일정 시간 후 <color=#9AFF02>부활</color>합니다. <color=#9AFF02>진원단이 없을 때</color> 캐릭터는 <color=#9AFF02>일반 공격</color>만 사용합니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["strategy_guide_desc_0004"] = {  key = "strategy_guide_desc_0004",  scn = "选择<color=#9AFF02>体修、法修</color>等修炼方向的核心场所。\n· 修炼：持续增加<color=#9AFF02>属性</color>\n· 突破：提升境界，增加<color=#9AFF02>大量属性</color>\n· 服用修为丹：增加<color=#9AFF02>修炼经验</color>。\n· 服用突破丹：增加<color=#9AFF02>突破概率</color>，<color=#9AFF02>修复</color>突破失败留下的<color=#9AFF02>道伤</color>。",  tcn = "選擇<color=#9AFF02>體修、法修</color>等修煉方向的核心場所。\n· 修煉：持續增加<color=#9AFF02>屬性</color>\n· 突破：提升境界，增加<color=#9AFF02>大量屬性</color>\n· 服用修為丹：增加<color=#9AFF02>修煉經驗</color>。\n· 服用突破丹：增加<color=#9AFF02>突破概率</color>，<color=#9AFF02>修復</color>突破失敗留下的<color=#9AFF02>道傷</color>。",  en = "The core place to choose your cultivation path, such as <color=#9AFF02>Body Cultivator or Spell Cultivator</color>.\n· Cultivate: Continuously increases <color=#9AFF02>Attributes</color>\n· Breakthrough: Elevates your realm, greatly increasing <color=#9AFF02>Attributes</color>\n· Take Cultivation Pills: Increases <color=#9AFF02>Cultivation EXP</color>.\n· Take Breakthrough Pills: Increases <color=#9AFF02>Breakthrough Chance</color> and <color=#9AFF02>repairs</color> the <color=#9AFF02>Dao injuries</color> left by failed breakthroughs.",  ru = "Основное место для выбора направления культивации, такого как <color=#9AFF02>Телесный культиватор или Маг</color>.\n· Культивация: Постоянно увеличивает <color=#9AFF02>Характеристики</color>\n· Прорыв: Повышает вашу стадию, значительно увеличивая <color=#9AFF02>Характеристики</color>\n· Приём пилюль культивации: Увеличивает <color=#9AFF02>опыт культивации</color>.\n· Приём пилюль прорыва: Увеличивает <color=#9AFF02>шанс прорыва</color> и <color=#9AFF02>восстанавливает</color> <color=#9AFF02>травмы Дао</color>, оставшиеся после неудачных прорывов.",  jp = "<color=#9AFF02>体修、法修</color>などの修煉方向を選択する核心的な場所。\n· 修煉：持続的に<color=#9AFF02>属性</color>を増加\n· 突破：境界を上昇させ、<color=#9AFF02>大量の属性</color>を増加\n· 修為丹を服用：<color=#9AFF02>修煉経験値</color>を増加。\n· 突破丹を服用：<color=#9AFF02>突破確率</color>を増加し、突破失敗で残った<color=#9AFF02>道傷</color>を<color=#9AFF02>修復</color>。",  kr = "<color=#9AFF02>체수, 법수</color> 등 수행 방향을 선택하는 핵심 장소입니다.\n· 수행: 지속적으로 <color=#9AFF02>속성</color> 증가\n· 돌파: 경지 상승, <color=#9AFF02>대량 속성</color> 증가\n· 수행단 복용: <color=#9AFF02>수행 경험치</color> 증가.\n· 돌파단 복용: <color=#9AFF02>돌파 확률</color> 증가 및 돌파 실패 시 남은 <color=#9AFF02>도상</color> <color=#9AFF02>복구</color>.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["strategy_guide_desc_0005"] = {  key = "strategy_guide_desc_0005",  scn = "选择丹方后，炼制<color=#9AFF02>恢复丹、修为丹、突破丹</color>。\n材料的<color=#9AFF02>品质越高</color>，炼制出的丹药<color=#9AFF02>品质越高</color>。",  tcn = "選擇丹方後，煉製<color=#9AFF02>恢復丹、修為丹、突破丹</color>。\n材料的<color=#9AFF02>品質越高</color>，煉製出的丹藥<color=#9AFF02>品質越高</color>。",  en = "After selecting a recipe, refine <color=#9AFF02>Recovery Pills, Cultivation Pills, and Breakthrough Pills</color>.\nThe <color=#9AFF02>higher the quality</color> of the materials, the <color=#9AFF02>higher the quality</color> of the refined pills.",  ru = "После выбора рецепта можно создавать <color=#9AFF02>Восстанавливающие пилюли, Пилюли культивации и Пилюли прорыва</color>.\n<color=#9AFF02>Чем выше качество</color> материалов, тем <color=#9AFF02>выше качество</color> полученных пилюль.",  jp = "丹方を選択後、<color=#9AFF02>回復丹、修為丹、突破丹</color>を錬成する。\n材料の<color=#9AFF02>品質が高いほど</color>、錬成される丹薬の<color=#9AFF02>品質も高くなる</color>。",  kr = "단방 선택 후, <color=#9AFF02>회복단, 수행단, 돌파단</color>을 제련합니다.\n재료의 <color=#9AFF02>품질이 높을수록</color> 제련된 단약의 <color=#9AFF02>품질이 높아집니다</color>.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["strategy_guide_desc_0006"] = {  key = "strategy_guide_desc_0006",  scn = "选择图纸后，炼制<color=#9AFF02>攻击法宝、护身法宝</color>。\n材料的<color=#9AFF02>品质越高</color>，炼制出的法宝<color=#9AFF02>品质越高</color>。",  tcn = "選擇圖紙後，煉製<color=#9AFF02>攻擊法寶、護身法寶</color>。\n材料的<color=#9AFF02>品質越高</color>，煉製出的法寶<color=#9AFF02>品質越高</color>。",  en = "After selecting a blueprint, refine <color=#9AFF02>Offensive Treasures and Defensive Treasures</color>.\nThe <color=#9AFF02>higher the quality</color> of the materials, the <color=#9AFF02>higher the quality</color> of the refined treasures.",  ru = "После выбора чертежа можно создавать <color=#9AFF02>Атакующие сокровища и Оборонные сокровища</color>.\n<color=#9AFF02>Чем выше качество</color> материалов, тем <color=#9AFF02>выше качество</color> полученных сокровищ.",  jp = "設計図を選択後、<color=#9AFF02>攻撃法寶、護身法寶</color>を錬成する。\n材料の<color=#9AFF02>品質が高いほど</color>、錬成される法寶の<color=#9AFF02>品質も高くなる</color>。",  kr = "도면 선택 후, <color=#9AFF02>공격 법보, 호신 법보</color>를 제련합니다.\n재료의 <color=#9AFF02>품질이 높을수록</color> 제련된 법보의 <color=#9AFF02>품질이 높아집니다</color>.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["strategy_guide_desc_0007"] = {  key = "strategy_guide_desc_0007",  scn = "在宝阁购买种子后种植：\n· 灵药：<color=#9AFF02>收获一次</color>后需重新种植\n· 灵材：可<color=#9AFF02>多次收获</color>\n灵田可获得最高<color=#FFD306>天品</color>品质的灵药和灵材（宝阁与关卡战斗最多获得<color=#B15BFF>极品</color>）。",  tcn = "在寶閣購買種子後種植：\n· 靈藥：<color=#9AFF02>收穫一次</color>後需重新種植\n· 靈材：可<color=#9AFF02>多次收穫</color>\n靈田可獲得最高<color=#FFD306>天品</color>品質的靈藥和靈材（寶閣與關卡戰鬥最多獲得<color=#B15BFF>極品</color>）。",  en = "Plant seeds purchased from the Treasure Pavilion:\n· Spirit Herbs: Need to be replanted after <color=#9AFF02>one harvest</color>\n· Spirit Materials: Can be <color=#9AFF02>harvested multiple times</color>\nThe Spirit Field can yield spirit herbs and spirit materials of up to <color=#FFD306>Heavenly</color> quality (the Treasure Pavilion and stage combat yield up to <color=#B15BFF>Supreme</color>).",  ru = "Посадите семена, купленные в Сокровищнице:\n· Духовные травы: После <color=#9AFF02>одного сбора</color> их нужно пересаживать\n· Духовные материалы: Можно <color=#9AFF02>собирать несколько раз</color>\nНа Духовном поле можно получить духовные травы и материалы вплоть до <color=#FFD306>Небесного</color> качества (в Сокровищнице и боях на этапах можно получить максимум <color=#B15BFF>Превосходное</color>).",  jp = "宝閣で種を購入して栽培：\n· 霊薬：<color=#9AFF02>一度収穫</color>したら再植え付けが必要\n· 霊材：<color=#9AFF02>複数回収穫</color>可能\n霊田では最高<color=#FFD306>天品</color>品質の霊薬と霊材が入手可能（宝閣とステージ戦闘では最大<color=#B15BFF>極品</color>まで）。",  kr = "보물 전당에서 씨앗 구매 후 재배:\n· 영약: <color=#9AFF02>한 번 수확</color> 후 재파종 필요\n· 영재: <color=#9AFF02>여러 번 수확</color> 가능\n영농지에서는 최고 <color=#FFD306>천품</color> 품질의 영약과 영재를 획득할 수 있습니다 (보물 전당과 스테이지 전투에서는 최대 <color=#B15BFF>극품</color> 획득).",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["strategy_guide_desc_0008"] = {  key = "strategy_guide_desc_0008",  scn = "可对<color=#9AFF02>修炼台、炼丹室、炼器坊、灵田</color>进行<color=#9AFF02>升级</color>，增强各建筑功能，升级需要消耗<color=#9AFF02>材料和灵石</color>。",  tcn = "可對<color=#9AFF02>修煉台、煉丹室、煉器坊、靈田</color>進行<color=#9AFF02>升級</color>，增強各建築功能，升級需要消耗<color=#9AFF02>材料和靈石</color>。",  en = "You can <color=#9AFF02>upgrade</color> the <color=#9AFF02>Cultivation Platform, Alchemy Room, Artifact Forge, and Spirit Field</color> to enhance their functions. Upgrading consumes <color=#9AFF02>materials and Spirit Stones</color>.",  ru = "Вы можете <color=#9AFF02>улучшать</color> <color=#9AFF02>Платформу культивации, Алхимическую комнату, Мастерскую артефактов и Духовное поле</color> для улучшения их функций. Улучшение потребляет <color=#9AFF02>материалы и Духовные камни</color>.",  jp = "<color=#9AFF02>修練台、錬丹室、法宝鍛造所、霊田</color>を<color=#9AFF02>アップグレード</color>し、各施設の機能を強化できる。アップグレードには<color=#9AFF02>材料と霊石</color>が必要。",  kr = "<color=#9AFF02>수련대, 단약 제련실, 법보 제련방, 영농지</color>를 <color=#9AFF02>업그레이드</color>하여 각 건물 기능을 강화할 수 있습니다. 업그레이드에는 <color=#9AFF02>재료와 영석</color>이 소모됩니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["strategy_guide_desc_0009"] = {  key = "strategy_guide_desc_0009",  scn = "提供额外加成，在战斗与养成中带来不同体验。",  tcn = "提供額外加成，在戰鬥與養成中帶來不同體驗。",  en = "Provides additional bonuses, offering a different experience in combat and character development.",  ru = "Предоставляет дополнительные бонусы, создавая особый опыт в бою и развитии персонажа.",  jp = "追加のボーナスを提供し、戦闘と育成に異なる体験をもたらす。",  kr = "추가 보너스를 제공하여 전투와 육성에서 다양한 경험을 선사합니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["strategy_guide_desc_0010"] = {  key = "strategy_guide_desc_0010",  scn = "<color=#9AFF02>攻击类</color>：攻击、破防、会心（暴击）、会伤（爆伤）\n<color=#9AFF02>防御类</color>：防御、气血（血量）、会心抵抗（暴击抵抗）、会伤抵抗（爆伤抵抗）\n<color=#9AFF02>基础类</color>：真元（蓝量）",  tcn = "<color=#9AFF02>攻擊類</color>：攻擊、破防、會心（暴擊）、會傷（爆傷）\n<color=#9AFF02>防禦類</color>：防禦、氣血（血量）、會心抵抗（暴擊抵抗）、會傷抵抗（爆傷抵抗）\n<color=#9AFF02>基礎類</color>：真元（藍量）",  en = "<color=#9AFF02>Offensive</color>: ATK, PEN, Crit (Critical Rate), Crit DMG (Critical Damage)\n<color=#9AFF02>Defensive</color>: DEF, HP (Health), Crit RES (Critical Resistance), Crit DMG RES (Critical Damage Resistance)\n<color=#9AFF02>Basic</color>: EP (Energy Points)",  ru = "<color=#9AFF02>Атакующие</color>: Атака, Пробивание, Крит. шанс, Крит. урон\n<color=#9AFF02>Защитные</color>: Защита, HP (Здоровье), Сопротивление криту, Снижение крит. урона\n<color=#9AFF02>Базовые</color>: Истинная энергия",  jp = "<color=#9AFF02>攻撃系</color>：攻撃、貫通、会心率、会心ダメージ\n<color=#9AFF02>防御系</color>：防御、気血（HP）、会心抵抗、会心ダメージ抵抗\n<color=#9AFF02>基礎系</color>：真元（MP）",  kr = "<color=#9AFF02>공격형</color>: 공격, 관통, 치명타율, 치명타 피해\n<color=#9AFF02>방어형</color>: 방어, 기혈(HP), 치명타 저항, 치명타 피해 저항\n<color=#9AFF02>기본형</color>: 진원(MP)",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["strategy_guide_desc_0011"] = {  key = "strategy_guide_desc_0011",  scn = "分为<color=#9AFF02>攻击法宝</color>与<color=#9AFF02>护身法宝</color>。\n· <color=#9AFF02>主属性</color>：可升级，消耗<color=#9AFF02>养器灵韵</color>（分解法宝获得）\n· <color=#9AFF02>进阶属性（词条）</color>：最多4条，品质越高词条越多\n· <color=#9AFF02>词条</color>：打造或购买时随机获得，<color=#9AFF02>不可升级</color>、<color=#9AFF02>不可改变</color>\n· <color=#9AFF02>突破</color>：消耗<color=#9AFF02>淬宝灵魄</color>（分解紫色及以上法宝获得）",  tcn = "分為<color=#9AFF02>攻擊法寶</color>與<color=#9AFF02>護身法寶</color>。\n· <color=#9AFF02>主屬性</color>：可升級，消耗<color=#9AFF02>養器靈韻</color>（分解法寶獲得）\n· <color=#9AFF02>進階屬性（詞條）</color>：最多4條，品質越高詞條越多\n· <color=#9AFF02>詞條</color>：打造或購買時隨機獲得，<color=#9AFF02>不可升級</color>、<color=#9AFF02>不可改變</color>\n· <color=#9AFF02>突破</color>：消耗<color=#9AFF02>淬寶靈魄</color>（分解紫色及以上法寶獲得）",  en = "Divided into <color=#9AFF02>Offensive Treasures</color> and <color=#9AFF02>Defensive Treasures</color>.\n· <color=#9AFF02>Main Stat</color>: Can be upgraded by consuming <color=#9AFF02>Treasure Nurturing Spirit</color> (obtained by dismantling treasures)\n· <color=#9AFF02>Advanced Stats (Affixes)</color>: Up to 4 affixes; higher quality treasures have more affixes\n· <color=#9AFF02>Affixes</color>: Obtained randomly when crafting or purchasing, <color=#9AFF02>cannot be upgraded</color> or <color=#9AFF02>changed</color>\n· <color=#9AFF02>Breakthrough</color>: Consumes <color=#9AFF02>Treasure Refining Soul</color> (obtained by dismantling purple or higher quality treasures)",  ru = "Делятся на <color=#9AFF02>Атакующие сокровища</color> и <color=#9AFF02>Оборонные сокровища</color>.\n· <color=#9AFF02>Основная характеристика</color>: Можно улучшать, расходуя <color=#9AFF02>Дух взращивания сокровищ</color> (получается при разборе сокровищ)\n· <color=#9AFF02>Дополнительные характеристики (аффиксы)</color>: До 4 аффиксов; чем выше качество, тем больше аффиксов\n· <color=#9AFF02>Аффиксы</color>: Получаются случайно при создании или покупке, <color=#9AFF02>нельзя улучшить</color> или <color=#9AFF02>изменить</color>\n· <color=#9AFF02>Прорыв</color>: Требует <color=#9AFF02>Душу перековки сокровищ</color> (получается при разборе фиолетовых и более высококачественных сокровищ)",  jp = "<color=#9AFF02>攻撃法寶</color>と<color=#9AFF02>護身法寶</color>に分類される。\n· <color=#9AFF02>主属性</color>：<color=#9AFF02>養器霊韻</color>（法寶分解で獲得）を消費してアップグレード可能\n· <color=#9AFF02>進階属性（オプション）</color>：最大4つ。品質が高いほどオプション数が多い\n· <color=#9AFF02>オプション</color>：作成または購入時にランダム獲得。<color=#9AFF02>アップグレード不可</color>、<color=#9AFF02>変更不可</color>\n· <color=#9AFF02>突破</color>：<color=#9AFF02>砕宝霊魄</color>（紫色以上の法寶分解で獲得）を消費",  kr = "<color=#9AFF02>공격 법보</color>와 <color=#9AFF02>호신 법보</color>로 구분됩니다.\n· <color=#9AFF02>주 속성</color>: <color=#9AFF02>양기 영운</color>(법보 분해 시 획득)을 소비하여 업그레이드 가능\n· <color=#9AFF02>고급 속성(옵션)</color>: 최대 4개, 품질이 높을수록 옵션 증가\n· <color=#9AFF02>옵션</color>: 제작 또는 구매 시 무작위 획득, <color=#9AFF02>업그레이드 불가</color>, <color=#9AFF02>변경 불가</color>\n· <color=#9AFF02>돌파</color>: <color=#9AFF02>쇄보 영백</color>(보라색 이상 법보 분해 시 획득) 소비",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["strategy_guide_desc_0012"] = {  key = "strategy_guide_desc_0012",  scn = "在<color=#9AFF02>道行</color>处领悟和升级，在<color=#9AFF02>角色</color>界面装配，装配栏随境界解锁：\n· 练气境：<color=#9AFF02>2个</color>\n· 筑基境：<color=#9AFF02>4个</color>\n· 金丹境及以后：<color=#9AFF02>6个</color>\n战斗中可<color=#9AFF02>随时更换</color>道法，更换后道法进入<color=#9AFF02>冷却</color>。",  tcn = "在<color=#9AFF02>道行</color>處領悟和升級，在<color=#9AFF02>角色</color>介面裝配，裝配欄隨境界解鎖：\n· 練氣境：<color=#9AFF02>2個</color>\n· 築基境：<color=#9AFF02>4個</color>\n· 金丹境及以後：<color=#9AFF02>6個</color>\n戰鬥中可<color=#9AFF02>隨時更換</color>道法，更換後道法進入<color=#9AFF02>冷卻</color>。",  en = "Comprehend and upgrade Dao Arts in <color=#9AFF02>Cultivation</color>, then equip them in the <color=#9AFF02>Character</color> interface. Equipment slots unlock as your realm advances:\n· Qi Refining Realm: <color=#9AFF02>2 slots</color>\n· Foundation Establishment Realm: <color=#9AFF02>4 slots</color>\n· Golden Core Realm and beyond: <color=#9AFF02>6 slots</color>\nDuring combat, you can <color=#9AFF02>swap Dao Arts at any time</color>. After swapping, the Dao Art will enter <color=#9AFF02>cooldown</color>.",  ru = "Постигайте и улучшайте Техники Дао в разделе <color=#9AFF02>Культивация</color>, затем экипируйте их в интерфейсе <color=#9AFF02>Персонаж</color>. Слоты открываются по мере повышения вашей стадии:\n· Стадия Поглощения Ци: <color=#9AFF02>2 слота</color>\n· Стадия Закладки Основы: <color=#9AFF02>4 слота</color>\n· Стадия Золотого Ядра и выше: <color=#9AFF02>6 слотов</color>\nВ бою вы можете <color=#9AFF02>менять Техники Дао в любое время</color>. После замены техника уходит в <color=#9AFF02>перезарядку</color>.",  jp = "<color=#9AFF02>道行き</color>で悟りとアップグレードを行い、<color=#9AFF02>キャラクター</color>画面で装備する。装備スロットは境界に応じて解放：\n· 練気境：<color=#9AFF02>2個</color>\n· 築基境：<color=#9AFF02>4個</color>\n· 金丹境以降：<color=#9AFF02>6個</color>\n戦闘中は<color=#9AFF02>いつでも道法を変更</color>可能。変更後、道法は<color=#9AFF02>クールダウン</color>に入る。",  kr = "<color=#9AFF02>도력</color>에서 깨우치고 업그레이드하여 <color=#9AFF02>캐릭터</color> 인터페이스에서 장착합니다. 장착 슬롯은 경지에 따라 해금됩니다:\n· 연기경: <color=#9AFF02>2개</color>\n· 주기경: <color=#9AFF02>4개</color>\n· 금단경 이상: <color=#9AFF02>6개</color>\n전투 중 <color=#9AFF02>언제든지 도법 교체</color> 가능합니다. 교체 후 도법은 <color=#9AFF02>쿨다운</color>에 들어갑니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["strategy_guide_desc_0013"] = {  key = "strategy_guide_desc_0013",  scn = "存放所有<color=#9AFF02>材料、丹药、法宝、种子</color>。\n支持<color=#9AFF02>一键分解法宝</color>、<color=#9AFF02>一键出售物品</color>。",  tcn = "存放所有<color=#9AFF02>材料、丹藥、法寶、種子</color>。\n支援<color=#9AFF02>一鍵分解法寶</color>、<color=#9AFF02>一鍵出售物品</color>。",  en = "Stores all <color=#9AFF02>materials, pills, treasures, and seeds</color>.\nSupports <color=#9AFF02>One-Click Dismantle Treasures</color> and <color=#9AFF02>One-Click Sell Items</color>.",  ru = "Хранит все <color=#9AFF02>материалы, пилюли, сокровища и семена</color>.\nПоддерживает <color=#9AFF02>одно нажатие для разбора сокровищ</color> и <color=#9AFF02>одно нажатие для продажи предметов</color>.",  jp = "すべての<color=#9AFF02>材料、丹薬、法寶、種</color>を保管する。\n<color=#9AFF02>法寶一括分解</color>、<color=#9AFF02>アイテム一括売却</color>に対応。",  kr = "모든 <color=#9AFF02>재료, 단약, 법보, 씨앗</color>을 보관합니다.\n<color=#9AFF02>법보 일괄 분해</color>, <color=#9AFF02>아이템 일괄 판매</color>를 지원합니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["strategy_guide_desc_0014"] = {  key = "strategy_guide_desc_0014",  scn = "<color=#9AFF02>领悟</color>与<color=#9AFF02>升级</color>本修炼方向的<color=#9AFF02>道法</color>（技能）。\n所需<color=#9AFF02>道法心得</color>与<color=#9AFF02>道法顿悟</color>通过论道战斗获得；产出随<color=#9AFF02>时间</color>和<color=#9AFF02>层数</color>累积，需在<color=#9AFF02>论道</color>界面<color=#9AFF02>手动领取</color>。",  tcn = "<color=#9AFF02>領悟</color>與<color=#9AFF02>升級</color>本修煉方向的<color=#9AFF02>道法</color>（技能）。\n所需<color=#9AFF02>道法心得</color>與<color=#9AFF02>道法頓悟</color>通過論道戰鬥獲得；產出隨<color=#9AFF02>時間</color>和<color=#9AFF02>層數</color>累積，需在<color=#9AFF02>論道</color>介面<color=#9AFF02>手動領取</color>。",  en = "<color=#9AFF02>Comprehend</color> and <color=#9AFF02>upgrade</color> the <color=#9AFF02>Dao Arts</color> (skills) of your chosen cultivation path.\nThe required <color=#9AFF02>Dao Art Insights</color> and <color=#9AFF02>Dao Art Enlightenment</color> are obtained through Dao Discussion combat. Output accumulates over <color=#9AFF02>time</color> and <color=#9AFF02>floor count</color>, and must be <color=#9AFF02>manually claimed</color> in the <color=#9AFF02>Dao Discussion</color> interface.",  ru = "<color=#9AFF02>Постигайте</color> и <color=#9AFF02>улучшайте</color> <color=#9AFF02>Техники Дао</color> (навыки) выбранного направления культивации.\nНеобходимые <color=#9AFF02>Прозрения в техники Дао</color> и <color=#9AFF02>Просветления в техники Дао</color> получаются в боях Бесед о Дао. Добыча накапливается со <color=#9AFF02>временем</color> и <color=#9AFF02>этажами</color>, и её необходимо <color=#9AFF02>забрать вручную</color> в интерфейсе <color=#9AFF02>Бесед о Дао</color>.",  jp = "自身の修煉方向の<color=#9AFF02>道法</color>（スキル）を<color=#9AFF02>悟り</color>、<color=#9AFF02>アップグレード</color>する。\n必要な<color=#9AFF02>道法の心得</color>と<color=#9AFF02>道法の悟り</color>は論道戦闘で獲得。獲得量は<color=#9AFF02>時間</color>と<color=#9AFF02>階層</color>に応じて蓄積され、<color=#9AFF02>論道</color>画面で<color=#9AFF02>手動受け取り</color>が必要。",  kr = "자신의 수행 방향에 맞는 <color=#9AFF02>도법</color>(스킬)을 <color=#9AFF02>깨우치고</color> <color=#9AFF02>업그레이드</color>합니다.\n필요한 <color=#9AFF02>도법 심득</color>과 <color=#9AFF02>도법 돈오</color>는 논도 전투를 통해 획득합니다. 획득량은 <color=#9AFF02>시간</color>과 <color=#9AFF02>층수</color>에 따라 누적되며, <color=#9AFF02>논도</color> 인터페이스에서 <color=#9AFF02>수동으로 수령</color>해야 합니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["strategy_guide_desc_0015"] = {  key = "strategy_guide_desc_0015",  scn = "验证战斗力的场所，难度逐步提升。\n可获得<color=#9AFF02>道法心得</color>与<color=#9AFF02>道法顿悟</color>材料，层数越高，道法心得<color=#9AFF02>产出越多</color>。",  tcn = "驗證戰鬥力的場所，難度逐步提升。\n可獲得<color=#9AFF02>道法心得</color>與<color=#9AFF02>道法頓悟</color>材料，層數越高，道法心得<color=#9AFF02>產出越多</color>。",  en = "A place to test your combat strength, with gradually increasing difficulty.\nYou can obtain <color=#9AFF02>Dao Art Insight</color> and <color=#9AFF02>Dao Art Enlightenment</color> materials. The higher the floor, the <color=#9AFF02>greater the output</color> of Dao Art Insights.",  ru = "Место для проверки вашей боевой мощи, сложность постепенно возрастает.\nМожно получить материалы <color=#9AFF02>Прозрений в техники Дао</color> и <color=#9AFF02>Просветлений в техники Дао</color>. Чем выше этаж, тем <color=#9AFF02>больше</color> вы получаете Прозрений.",  jp = "戦闘力を試す場所。難易度は段階的に上昇する。\n<color=#9AFF02>道法の心得</color>と<color=#9AFF02>道法の悟り</color>素材を獲得可能。階層が高いほど、道法の心得の<color=#9AFF02>獲得量が増加</color>する。",  kr = "전투력을 검증하는 장소로, 난이도가 단계적으로 상승합니다.\n<color=#9AFF02>도법 심득</color>과 <color=#9AFF02>도법 돈오</color> 재료를 획득할 수 있습니다. 층수가 높을수록 도법 심득 <color=#9AFF02>획득량이 증가</color>합니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["strategy_guide_desc_0016"] = {  key = "strategy_guide_desc_0016",  scn = "消耗<color=#9AFF02>灵石</color>购买商品，最高可购<color=#9AFF02>极品</color>品质道具：\n· 练气期开放<color=#9AFF02>4格</color>，随境界逐步增加\n· 商品需<color=#9AFF02>手动刷新</color>，每次<color=#9AFF02>刷新</color>所需灵石<color=#9AFF02>递增</color>\n· <color=#9AFF02>灵石商店</color>：材料、法宝、丹药、道法心得、养器灵韵等\n· <color=#9AFF02>种子商店</color>：各类种子（灵田种植所需）",  tcn = "消耗<color=#9AFF02>靈石</color>購買商品，最高可購<color=#9AFF02>極品</color>品質道具：\n· 練氣期開放<color=#9AFF02>4格</color>，隨境界逐步增加\n· 商品需<color=#9AFF02>手動刷新</color>，每次<color=#9AFF02>刷新</color>所需靈石<color=#9AFF02>遞增</color>\n· <color=#9AFF02>靈石商店</color>：材料、法寶、丹藥、道法心得、養器靈韻等\n· <color=#9AFF02>種子商店</color>：各類種子（靈田種植所需）",  en = "Spend <color=#9AFF02>Spirit Stones</color> to purchase items, with the highest obtainable quality being <color=#9AFF02>Supreme</color>:\n· Qi Refining stage opens <color=#9AFF02>4 slots</color>, increasing gradually as your realm advances\n· The shop requires <color=#9AFF02>manual refresh</color>; each <color=#9AFF02>refresh</color> costs an <color=#9AFF02>increasing</color> number of Spirit Stones\n· <color=#9AFF02>Spirit Stone Shop</color>: Materials, Treasures, Pills, Dao Art Insights, Treasure Nurturing Spirit, etc.\n· <color=#9AFF02>Seed Shop</color>: Various types of seeds (required for Spirit Field planting)",  ru = "Тратьте <color=#9AFF02>Духовные камни</color> для покупки предметов, максимальное доступное качество — <color=#9AFF02>Превосходное</color>:\n· На стадии Поглощения Ци открывается <color=#9AFF02>4 ячейки</color>, их количество увеличивается по мере повышения стадии\n· Требуется <color=#9AFF02>ручное обновление</color> магазина; каждое <color=#9AFF02>обновление</color> стоит <color=#9AFF02>всё больше</color> Духовных камней\n· <color=#9AFF02>Магазин Духовных камней</color>: Материалы, Сокровища, Пилюли, Прозрения в техники Дао, Дух взращивания сокровищ и т.д.\n· <color=#9AFF02>Магазин семян</color>: Различные виды семян (необходимы для посадки на Духовном поле)",  jp = "<color=#9AFF02>霊石</color>を消費して商品を購入。最大<color=#9AFF02>極品</color>品質まで購入可能：\n· 練気期で<color=#9AFF02>4枠</color>開放、境界に応じて段階的に増加\n· 商品は<color=#9AFF02>手動で更新</color>が必要。更新ごとに必要<color=#9AFF02>霊石</color>が<color=#9AFF02>増加</color>\n· <color=#9AFF02>霊石商店</color>：材料、法寶、丹薬、道法の心得、養器霊韻など\n· <color=#9AFF02>種ショップ</color>：各種種（霊田栽培に必要）",  kr = "<color=#9AFF02>영석</color>을 소비하여 상품을 구매합니다. 최대 <color=#9AFF02>극품</color> 품질까지 구매 가능:\n· 연하기에 <color=#9AFF02>4칸</color> 개방, 경지에 따라 점진적 증가\n· 상품은 <color=#9AFF02>수동 새로 고침</color> 필요, 새로 고침 시마다 필요 <color=#9AFF02>영석</color> <color=#9AFF02>증가</color>\n· <color=#9AFF02>영석 상점</color>: 재료, 법보, 단약, 도법 심득, 양기 영운 등\n· <color=#9AFF02>씨앗 상점</color>: 각종 씨앗 (영농지 재배에 필요)",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["strategy_guide_desc_0017"] = {  key = "strategy_guide_desc_0017",  scn = "选择不同境界的地区关卡，每个地区含<color=#9AFF02>3个</color>小关卡与<color=#9AFF02>1个</color>首领关卡。\n· 解锁条件：<color=#9AFF02>境界符合</color>且<color=#9AFF02>通关</color>前一首领关卡\n· 小关卡<color=#9AFF02>难度递增</color>，分别掉落<color=#00DB00>中品</color>、<color=#00E3E3>上品</color>、<color=#B15BFF>极品</color>品质材料\n· 是获取<color=#9AFF02>妖兽材料、灵药、灵材、灵矿</color>的主要场所",  tcn = "選擇不同境界的地區關卡，每個地區含<color=#9AFF02>3個</color>小關卡與<color=#9AFF02>1個</color>首領關卡。\n· 解鎖條件：<color=#9AFF02>境界符合</color>且<color=#9AFF02>通關</color>前一首領關卡\n· 小關卡<color=#9AFF02>難度遞增</color>，分別掉落<color=#00DB00>中品</color>、<color=#00E3E3>上品</color>、<color=#B15BFF>極品</color>品質材料\n· 是獲取<color=#9AFF02>妖獸材料、靈藥、靈材、靈礦</color>的主要場所",  en = "Select region stages based on your realm. Each region contains <color=#9AFF02>3 small stages</color> and <color=#9AFF02>1 boss stage</color>.\n· Unlock Conditions: <color=#9AFF02>Meet the realm requirement</color> and <color=#9AFF02>clear</color> the previous boss stage\n· Small stages have <color=#9AFF02>increasing difficulty</color> and drop materials of <color=#00DB00>Medium</color>, <color=#00E3E3>Superior</color>, and <color=#B15BFF>Supreme</color> quality respectively\n· The main source for <color=#9AFF02>demon beast materials, spirit herbs, spirit materials, and spirit ores</color>",  ru = "Выберите региональные этапы в соответствии с вашей стадией. Каждый регион содержит <color=#9AFF02>3 малых этапа</color> и <color=#9AFF02>1 этап с боссом</color>.\n· Условия открытия: <color=#9AFF02>Соответствующая стадия</color> и <color=#9AFF02>прохождение</color> предыдущего этапа с боссом\n· Малые этапы имеют <color=#9AFF02>возрастающую сложность</color> и дают материалы <color=#00DB00>Среднего</color>, <color=#00E3E3>Высшего</color> и <color=#B15BFF>Превосходного</color> качества соответственно\n· Основной источник <color=#9AFF02>материалов демонических зверей, духовных трав, духовных материалов и духовных руд</color>",  jp = "境界に応じた地域ステージを選択。各地域には<color=#9AFF02>3つの小ステージ</color>と<color=#9AFF02>1つのボスステージ</color>が含まれる。\n· 解放条件：<color=#9AFF02>境界が適合</color>し、前のボスステージを<color=#9AFF02>クリア</color>する\n· 小ステージは<color=#9AFF02>難易度が段階的に上昇</color>し、それぞれ<color=#00DB00>中品</color>、<color=#00E3E3>上品</color>、<color=#B15BFF>極品</color>品質の材料をドロップ\n· <color=#9AFF02>妖兽素材、霊薬、霊材、霊鉱</color>の主な入手場所",  kr = "경지에 따라 지역 스테이지를 선택합니다. 각 지역은 <color=#9AFF02>3개의 소형 스테이지</color>와 <color=#9AFF02>1개의 우두머리 스테이지</color>로 구성됩니다.\n· 해금 조건: <color=#9AFF02>경지 충족</color> 및 이전 우두머리 스테이지 <color=#9AFF02>클리어</color>\n· 소형 스테이지는 <color=#9AFF02>난이도가 증가</color>하며, 각각 <color=#00DB00>중품</color>, <color=#00E3E3>상품</color>, <color=#B15BFF>극품</color> 품질의 재료를 드랍합니다.\n· <color=#9AFF02>요수 재료, 영약, 영재, 영광</color>의 주요 획득처입니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
