data["task_tite_desc_0001"] = {  key = "task_tite_desc_0001",  scn = "初入仙途【1/4】\n· 在 【洞府】 - 【修炼台】 中选择任意修炼方向，并突破至【练气期一层】。",  tcn = "初入仙途【1/4】\n· 在 【洞府】 - 【修煉台】 中選擇任意修煉方向，並突破至【練氣期一層】。",  en = "First Steps into Immortality [1/4]\n· Select any cultivation path in [Abode] - [Cultivation Platform] and break through to [Qi Refining Level 1].",  ru = "Первые шаги на пути бессмертных [1/4]\n· Выберите любое направление культивации в [Обитель] - [Платформа культивации] и совершите прорыв до [1-го уровня Поглощения ци].",  jp = "仙道入門【1/4】\n· 【洞府】-【修練台】で任意の修煉方向を選択し、【練気期一層】まで突破せよ。",  kr = "첫 걸음, 신선의 길 [1/4]\n· [동부] - [수련대]에서 원하는 수행 방향을 선택하고 [연기 1층]까지 돌파하세요.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0002"] = {  key = "task_tite_desc_0002",  scn = "初入仙途【2/4】\n· 在 【洞府】 - 【修炼台】 中选择任意修炼方向，并突破至【练气期四层】。若感觉苦修太慢，不妨服用【凝气散或炼血丹】。",  tcn = "初入仙途【2/4】\n· 在 【洞府】 - 【修煉台】 中選擇任意修煉方向，並突破至【練氣期四層】。若感覺苦修太慢，不妨服用【凝氣散或煉血丹】。",  en = "First Steps into Immortality [2/4]\n· Select any cultivation path in [Abode] - [Cultivation Platform] and break through to [Qi Refining Level 4]. If you find cultivation too slow, consider taking [Qi Coagulation Powder or Blood Refining Pill].",  ru = "Первые шаги на пути бессмертных [2/4]\n· Выберите любое направление культивации в [Обитель] - [Платформа культивации] и совершите прорыв до [4-го уровня Поглощения ци]. Если культивация кажется слишком медленной, попробуйте принять [Порошок Конденсации Ци или Пилюлю Очищения Крови].",  jp = "仙道入門【2/4】\n· 【洞府】-【修練台】で任意の修煉方向を選択し、【練気期四層】まで突破せよ。苦修が遅すぎると感じたら、【凝気散または練血丹】を服用するとよい。",  kr = "첫 걸음, 신선의 길 [2/4]\n· [동부] - [수련대]에서 원하는 수행 방향을 선택하고 [연기 4층]까지 돌파하세요. 수행이 너무 느리다면 [응기산 또는 연혈단]을 복용해 보세요.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0003"] = {  key = "task_tite_desc_0003",  scn = "齐头并进【1/3】\n· 在 【洞府】-【修炼台】中选择另外的修炼方向，并突破至【练气期三层】。多余的材料，不妨炼些其它修炼方向的丹药，单修固然快，毕竟双修无短板。",  tcn = "齊頭並進【1/3】\n· 在 【洞府】-【修煉台】中選擇另外的修煉方向，並突破至【練氣期三層】。多餘的材料，不妨煉些其它修煉方向的丹藥，單修固然快，畢竟雙修無短板。",  en = "Advancing Together [1/3]\n· Select a different cultivation path in [Abode] - [Cultivation Platform] and break through to [Qi Refining Level 3]. Use excess materials to refine pills for other paths. While focusing on one path is faster, cultivating both leaves no weaknesses.",  ru = "Совместное продвижение [1/3]\n· Выберите другое направление культивации в [Обитель] - [Платформа культивации] и совершите прорыв до [3-го уровня Поглощения ци]. Используйте излишние материалы для создания пилюль для других направлений. Хотя сосредоточение на одном пути быстрее, развитие обоих не даёт слабых мест.",  jp = "共に前進【1/3】\n· 【洞府】-【修練台】で別の修煉方向を選択し、【練気期三層】まで突破せよ。余った材料で他の修煉方向の丹薬を煉るのがよい。単修も早いが、双修に短板なし。",  kr = "함께 나아가기 [1/3]\n· [동부] - [수련대]에서 다른 수행 방향을 선택하고 [연기 3층]까지 돌파하세요. 남는 재료로 다른 수행 방향의 단약을 제련해 보세요. 한 방향만 수련하는 것이 빠르지만, 두 방향 모두 수련하면 약점이 없습니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0004"] = {  key = "task_tite_desc_0004",  scn = "初入仙途【3/4】 \n· 在 【洞府】 - 【修炼台】 中选择任意修炼方向，并突破至【练气期七层】。修为丹品质越高，增加修为越多。",  tcn = "初入仙途【3/4】 \n· 在 【洞府】 - 【修煉台】 中選擇任意修煉方向，並突破至【練氣期七層】。修為丹品質越高，增加修為越多。",  en = "First Steps into Immortality [3/4]\n· Select any cultivation path in [Abode] - [Cultivation Platform] and break through to [Qi Refining Level 7]. The higher the quality of the Cultivation Pill, the more cultivation it provides.",  ru = "Первые шаги на пути бессмертных [3/4]\n· Выберите любое направление культивации в [Обитель] - [Платформа культивации] и совершите прорыв до [7-го уровня Поглощения ци]. Чем выше качество Пилюли культивации, тем больше она даёт опыта.",  jp = "仙道入門【3/4】\n· 【洞府】-【修練台】で任意の修煉方向を選択し、【練気期七層】まで突破せよ。修為丹の品質が高いほど、得られる修為が増える。",  kr = "첫 걸음, 신선의 길 [3/4]\n· [동부] - [수련대]에서 원하는 수행 방향을 선택하고 [연기 7층]까지 돌파하세요. 수행단의 품질이 높을수록 증가하는 수행량이 많아집니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0005"] = {  key = "task_tite_desc_0005",  scn = "初入仙途【4/4】 \n· 在 【洞府】 - 【修炼台】 中选择任意修炼方向，并突破至【筑基前期一层】。",  tcn = "初入仙途【4/4】 \n· 在 【洞府】 - 【修煉台】 中選擇任意修煉方向，並突破至【築基前期一層】。",  en = "First Steps into Immortality [4/4]\n· Select any cultivation path in [Abode] - [Cultivation Platform] and break through to [Early Foundation Establishment Level 1].",  ru = "Первые шаги на пути бессмертных [4/4]\n· Выберите любое направление культивации в [Обитель] - [Платформа культивации] и совершите прорыв до [1-го уровня ранней стадии Закладки основы].",  jp = "仙道入門【4/4】\n· 【洞府】-【修練台】で任意の修煉方向を選択し、【築基前期一層】まで突破せよ。",  kr = "첫 걸음, 신선의 길 [4/4]\n· [동부] - [수련대]에서 원하는 수행 방향을 선택하고 [주기 전기 1층]까지 돌파하세요.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0006"] = {  key = "task_tite_desc_0006",  scn = "丹师传承【1/3】 \n· 在【洞府】-【炼丹房】中炼制【气血丹】。气血丹可自动恢复气血，长久保持战斗。\n· 【气血丹】材料：妖兽肉。\n· 妖兽肉：落云谷击杀妖兽掉落。",  tcn = "丹師傳承【1/3】 \n· 在【洞府】-【煉丹房】中煉製【氣血丹】。氣血丹可自動恢復氣血，長久保持戰鬥。\n· 【氣血丹】材料：妖獸肉。\n· 妖獸肉：落雲谷擊殺妖獸掉落。",  en = "Alchemist Legacy [1/3] \n· Refine [Health Pill] in [Abode] - [Alchemy Room]. Health Pill automatically restores Health, allowing you to stay in combat longer.\n· [Health Pill] Materials: Beast Flesh.\n· Beast Flesh: Dropped by defeating demon beasts in Falling Cloud Valley.",  ru = "Наследие алхимика [1/3] \n· Создайте [Пилюлю Ци и Крови] в [Обитель] - [Алхимическая комната]. Пилюля Ци и Крови автоматически восстанавливает здоровье, позволяя дольше оставаться в бою.\n· Материалы [Пилюли Ци и Крови]: Плоть зверя.\n· Плоть зверя: Выпадает при убийстве демонических зверей в Долине Падающих Туч.",  jp = "丹師の伝承【1/3】 \n· 【洞府】-【錬丹室】で【気血丹】を錬成せよ。気血丹は自動的に気血を回復し、戦闘を長く維持できる。\n· 【気血丹】の材料：妖兽肉。\n· 妖兽肉：落雲谷で妖兽を討伐して入手。",  kr = "단사 계승 [1/3] \n· [동부] - [단약 제련실]에서 [기혈단]을 제련하세요. 기혈단은 자동으로 기혈을 회복하여 전투를 오래 유지시켜 줍니다.\n· [기혈단] 재료: 요수육.\n· 요수육: 낙운곡에서 요수 처치 시 드랍.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0007"] = {  key = "task_tite_desc_0007",  scn = "丹师传承【2/3】\n· 在【洞府】-【炼丹房】中炼制【凝气散或炼血丹】，在【洞府】-【修炼台】中服用可加速修炼。\n· 【凝气散或炼血丹】材料：妖兽内丹、精血。\n· 妖兽内丹、精血：落云谷击杀妖兽掉落。",  tcn = "丹師傳承【2/3】\n· 在【洞府】-【煉丹房】中煉製【凝氣散或煉血丹】，在【洞府】-【修煉台】中服用可加速修煉。\n· 【凝氣散或煉血丹】材料：妖獸內丹、精血。\n· 妖獸內丹、精血：落雲谷擊殺妖獸掉落。",  en = "Alchemist Legacy [2/3]\n· Refine [Qi Coagulation Powder or Blood Refining Pill] in [Abode] - [Alchemy Room]. Taking it in [Abode] - [Cultivation Platform] accelerates cultivation.\n· [Qi Coagulation Powder or Blood Refining Pill] Materials: Demon Beast Core, Vital Blood.\n· Demon Beast Core, Vital Blood: Dropped by defeating demon beasts in Falling Cloud Valley.",  ru = "Наследие алхимика [2/3]\n· Создайте [Порошок Конденсации Ци или Пилюлю Очищения Крови] в [Обитель] - [Алхимическая комната]. Приём в [Обитель] - [Платформа культивации] ускоряет культивацию.\n· Материалы [Порошка Конденсации Ци или Пилюли Очищения Крови]: Ядро демонического зверя, жизненная кровь.\n· Ядро демонического зверя, жизненная кровь: Выпадает при убийстве демонических зверей в Долине Падающих Туч.",  jp = "丹師の伝承【2/3】\n· 【洞府】-【錬丹室】で【凝気散または練血丹】を錬成し、【洞府】-【修練台】で服用すると修煉を加速できる。\n· 【凝気散または練血丹】の材料：妖兽の内丹、精血。\n· 妖兽の内丹、精血：落雲谷で妖兽を討伐して入手。",  kr = "단사 계승 [2/3]\n· [동부] - [단약 제련실]에서 [응기산 또는 연혈단]을 제련하고, [동부] - [수련대]에서 복용하면 수행을 가속화할 수 있습니다.\n· [응기산 또는 연혈단] 재료: 요수 내단, 정혈.\n· 요수 내단, 정혈: 낙운곡에서 요수 처치 시 드랍.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0008"] = {  key = "task_tite_desc_0008",  scn = "丹师传承【3/3】\n· 在【洞府】-【炼丹房】中炼制【真元丹】。补充真元，保持道法持久释放。\n· 【真元丹】材料：妖兽肉。\n· 妖兽肉：落云谷击杀妖兽掉落。",  tcn = "丹師傳承【3/3】\n· 在【洞府】-【煉丹房】中煉製【真元丹】。補充真元，保持道法持久釋放。\n· 【真元丹】材料：妖獸肉。\n· 妖獸肉：落雲谷擊殺妖獸掉落。",  en = "Alchemist Legacy [3/3]\n· Refine [True Energy Pill] in [Abode] - [Alchemy Room]. Restores True Energy, allowing sustained use of Dao Arts.\n· [True Energy Pill] Materials: Beast Flesh.\n· Beast Flesh: Dropped by defeating demon beasts in Falling Cloud Valley.",  ru = "Наследие алхимика [3/3]\n· Создайте [Пилюлю Истинной Энергии] в [Обитель] - [Алхимическая комната]. Восстанавливает Истинную энергию, позволяя дольше использовать техники Дао.\n· Материалы [Пилюли Истинной Энергии]: Плоть зверя.\n· Плоть зверя: Выпадает при убийстве демонических зверей в Долине Падающих Туч.",  jp = "丹師の伝承【3/3】\n· 【洞府】-【錬丹室】で【真元丹】を錬成せよ。真元を補充し、道法を持続的に放つ。\n· 【真元丹】の材料：妖兽肉。\n· 妖兽肉：落雲谷で妖兽を討伐して入手。",  kr = "단사 계승 [3/3]\n· [동부] - [단약 제련실]에서 [진원단]을 제련하세요. 진원을 보충하여 도법을 지속적으로 사용할 수 있습니다.\n· [진원단] 재료: 요수육.\n· 요수육: 낙운곡에서 요수 처치 시 드랍.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0009"] = {  key = "task_tite_desc_0009",  scn = "论道争锋【1/3】\n· 在【论道】-【镇妖塔】中闯关前行。既能获得历代前辈遗留的道法心得，可在【道行】中升级道法。",  tcn = "論道爭鋒【1/3】\n· 在【論道】-【鎮妖塔】中闖關前行。既能獲得歷代前輩遺留的道法心得，可在【道行】中升級道法。",  en = "Dao Debate Duel [1/3]\n· Progress through the stages in [Dao Discussion] - [Demon Suppression Tower]. You can obtain Dao Art Insights left by past masters, which can be used to upgrade Dao Arts in [Cultivation].",  ru = "Дуэль в беседах о Дао [1/3]\n· Проходите этажи в [Беседа о Дао] - [Башня Усмирения Демонов]. Вы получите Прозрения в техники Дао, оставленные мастерами прошлого, которые можно использовать для улучшения техник Дао в [Культивация].",  jp = "論道闘法【1/3】\n· 【論道】-【鎮妖塔】で階層を進めよ。歴代の先輩が遺した道法の心得を獲得でき、【道行き】で道法をアップグレードできる。",  kr = "논도 격돌 [1/3]\n· [논도] - [요괴 봉인 탑]에서 층을 진행하세요. 역대 선배들이 남긴 도법 심득을 획득할 수 있으며, [도력]에서 도법을 업그레이드할 수 있습니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0010"] = {  key = "task_tite_desc_0010",  scn = "论道争锋【2/4】\n· 在【论道】-【镇妖塔】中闯关前行。闯关层数越高，所获道法心得越多。",  tcn = "論道爭鋒【2/4】\n· 在【論道】-【鎮妖塔】中闖關前行。闖關層數越高，所獲道法心得越多。",  en = "Dao Debate Duel [2/4]\n· Progress through the stages in [Dao Discussion] - [Demon Suppression Tower]. The higher the stage you reach, the more Dao Art Insights you will obtain.",  ru = "Дуэль в беседах о Дао [2/4]\n· Проходите этажи в [Беседа о Дао] - [Башня Усмирения Демонов]. Чем выше этаж вы пройдёте, тем больше Прозрений в техники Дао получите.",  jp = "論道闘法【2/4】\n· 【論道】-【鎮妖塔】で階層を進めよ。進んだ階層が高いほど、獲得できる道法の心得が増える。",  kr = "논도 격돌 [2/4]\n· [논도] - [요괴 봉인 탑]에서 층을 진행하세요. 진행한 층수가 높을수록 획득하는 도법 심득이 많아집니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0011"] = {  key = "task_tite_desc_0011",  scn = "论道争锋【3/4】\n· 在【论道】-【镇妖塔】中闯关前行。闯关层数越高，所获道法心得越多。",  tcn = "論道爭鋒【3/4】\n· 在【論道】-【鎮妖塔】中闖關前行。闖關層數越高，所獲道法心得越多。",  en = "Dao Debate Duel [3/4]\n· Progress through the stages in [Dao Discussion] - [Demon Suppression Tower]. The higher the stage you reach, the more Dao Art Insights you will obtain.",  ru = "Дуэль в беседах о Дао [3/4]\n· Проходите этажи в [Беседа о Дао] - [Башня Усмирения Демонов]. Чем выше этаж вы пройдёте, тем больше Прозрений в техники Дао получите.",  jp = "論道闘法【3/4】\n· 【論道】-【鎮妖塔】で階層を進めよ。進んだ階層が高いほど、獲得できる道法の心得が増える。",  kr = "논도 격돌 [3/4]\n· [논도] - [요괴 봉인 탑]에서 층을 진행하세요. 진행한 층수가 높을수록 획득하는 도법 심득이 많아집니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0012"] = {  key = "task_tite_desc_0012",  scn = "论道争锋【4/4】\n· 在【论道】-【镇妖塔】中闯关前行。练气登顶，可冲筑基。",  tcn = "論道爭鋒【4/4】\n· 在【論道】-【鎮妖塔】中闖關前行。練氣登頂，可衝築基。",  en = "Dao Debate Duel [4/4]\n· Progress through the stages in [Dao Discussion] - [Demon Suppression Tower]. Reach the peak of Qi Refining to pave the way for Foundation Establishment.",  ru = "Дуэль в беседах о Дао [4/4]\n· Проходите этажи в [Беседа о Дао] - [Башня Усмирения Демонов]. Достигните пика Поглощения ци, чтобы проложить путь к Закладке основы.",  jp = "論道闘法【4/4】\n· 【論道】-【鎮妖塔】で階層を進めよ。練気を極め、築基へと駆け上がれ。",  kr = "논도 격돌 [4/4]\n· [논도] - [요괴 봉인 탑]에서 층을 진행하세요. 연기 정상에 오르면 주기로 나아갈 수 있습니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0013"] = {  key = "task_tite_desc_0013",  scn = "直面妖王【1/3】\n· 在【世界】-【落云谷】中选择【谷中】前往历练，可获得上品材料，当然妖兽也会更强，但妖王不会注意到这里。",  tcn = "直面妖王【1/3】\n· 在【世界】-【落雲谷】中選擇【谷中】前往歷練，可獲得中品材料，當然妖獸也會更強，但妖王不會注意到這裡。",  en = "Facing the Demon King [1/3]\n· Select [Mid Valley] in [World] - [Falling Cloud Valley] to venture forth. You can obtain Superior materials, but the demon beasts will be stronger. However, the Demon King won\'t notice you here.",  ru = "Столкновение с Королём демонов [1/3]\n· Выберите [Середина долины] в [Мир] - [Долина Падающих Туч] для испытания. Вы получите материалы высшего качества, но демонические звери будут сильнее. Однако Король демонов не заметит вас здесь.",  jp = "妖王との対峙【1/3】\n· 【世界】-【落雲谷】で【谷中】を選択して修行へ向かう。上品の材料が得られるが、もちろん妖兽も強くなる。ただし妖王はここに気づかない。",  kr = "요왕과 맞서다 [1/3]\n· [세계] - [낙운곡]에서 [곡중]을 선택하여 수행을 떠나세요. 상품 재료를 획득할 수 있으며, 물론 요수도 더 강해집니다. 하지만 요왕은 이곳을 눈치채지 못합니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0014"] = {  key = "task_tite_desc_0014",  scn = "直面妖王【2/3】\n· 在【世界】-【落云谷】中选择【谷内】前往历练，可获得极品材料，距离妖王越来越近了。",  tcn = "直面妖王【2/3】\n· 在【世界】-【落雲谷】中選擇【谷內】前往歷練，可獲得極品材料，距離妖王越來越近了。",  en = "Facing the Demon King [2/3]\n· Select [Inner Valley] in [World] - [Falling Cloud Valley] to venture forth. You can obtain Supreme materials, drawing ever closer to the Demon King.",  ru = "Столкновение с Королём демонов [2/3]\n· Выберите [Внутренняя долина] в [Мир] - [Долина Падающих Туч] для испытания. Вы получите превосходные материалы, приближаясь к Королю демонов.",  jp = "妖王との対峙【2/3】\n· 【世界】-【落雲谷】で【谷内】を選択して修行へ向かう。極品の材料が得られ、妖王にますます近づく。",  kr = "요왕과 맞서다 [2/3]\n· [세계] - [낙운곡]에서 [곡내]를 선택하여 수행을 떠나세요. 극품 재료를 획득할 수 있으며, 요왕에게 점점 가까워집니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0015"] = {  key = "task_tite_desc_0015",  scn = "直面妖王【3/3】\n· 在【世界】-【落云谷】中选择【妖王】前往历练，可获得洞府进阶材料，是时候解决妖王了。",  tcn = "直面妖王【3/3】\n· 在【世界】-【落雲谷】中選擇【妖王】前往歷練，可獲得洞府進階材料，是時候解決妖王了。",  en = "Facing the Demon King [3/3]\n· Select [Demon King] in [World] - [Falling Cloud Valley] to venture forth. You can obtain Abode upgrade materials. It\'s time to deal with the Demon King.",  ru = "Столкновение с Королём демонов [3/3]\n· Выберите [Король демонов] в [Мир] - [Долина Падающих Туч] для испытания. Вы получите материалы для улучшения обители. Пришло время разобраться с Королём демонов.",  jp = "妖王との対峙【3/3】\n· 【世界】-【落雲谷】で【妖王】を選択して修行へ向かう。洞府の進階材料が得られる。妖王を倒す時が来た。",  kr = "요왕과 맞서다 [3/3]\n· [세계] - [낙운곡]에서 [요왕]을 선택하여 수행을 떠나세요. 동부 고급 재료를 획득할 수 있습니다. 이제 요왕을 처리할 때입니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0016"] = {  key = "task_tite_desc_0016",  scn = "法宝伴身【1/4】\n· 在【洞府】-【炼器坊】中炼制1次法宝。\n· 【法宝】材料：妖兽皮、骨。\n· 妖兽皮、骨：落云谷击杀妖兽掉落。",  tcn = "法寶伴身【1/4】\n· 在【洞府】-【煉器坊】中煉製1次法寶。\n· 【法寶】材料：妖獸皮、骨。\n· 妖獸皮、骨：落雲谷擊殺妖獸掉落。",  en = "Treasures by Your Side [1/4]\n· Refine a Treasure once in [Abode] - [Artifact Forge].\n· [Treasure] Materials: Beast Hide, Bone.\n· Beast Hide, Bone: Dropped by defeating demon beasts in Falling Cloud Valley.",  ru = "Сокровища на твоей стороне [1/4]\n· Создайте Сокровище один раз в [Обитель] - [Мастерская артефактов].\n· Материалы [Сокровища]: Шкура зверя, Кость.\n· Шкура зверя, Кость: Выпадает при убийстве демонических зверей в Долине Падающих Туч.",  jp = "法宝随身【1/4】\n· 【洞府】-【法宝鍛造所】で法寶を1回錬成せよ。\n· 【法寶】の材料：妖兽の皮、骨。\n· 妖兽の皮、骨：落雲谷で妖兽を討伐して入手。",  kr = "법보와 함께 [1/4]\n· [동부] - [법보 제련방]에서 법보를 1회 제련하세요.\n· [법보] 재료: 요수 가죽, 뼈.\n· 요수 가죽, 뼈: 낙운곡에서 요수 처치 시 드랍.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0017"] = {  key = "task_tite_desc_0017",  scn = "法宝伴身【2/4】\n· 在【角色】-【法宝】中装配法宝，方可发挥其威能。",  tcn = "法寶伴身【2/4】\n· 在【角色】-【法寶】中裝配法寶，方可發揮其威能。",  en = "Treasures by Your Side [2/4]\n· Equip the Treasure in [Character] - [Treasures] to unleash its power.",  ru = "Сокровища на твоей стороне [2/4]\n· Экипируйте Сокровище в [Персонаж] - [Сокровища], чтобы раскрыть его силу.",  jp = "法宝随身【2/4】\n· 【キャラクター】-【法寶】で法寶を装備して、その威能を発揮せよ。",  kr = "법보와 함께 [2/4]\n· [캐릭터] - [법보]에서 법보를 장착해야 그 위력을 발휘할 수 있습니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0018"] = {  key = "task_tite_desc_0018",  scn = "法宝伴身【3/4】\n· 在【角色】-【法宝】中升级法宝，所需材料，需在【储物】-【一键分解】中分解多余法宝获得。",  tcn = "法寶伴身【3/4】\n· 在【角色】-【法寶】中升級法寶，所需材料，需在【儲物】-【一鍵分解】中分解多餘法寶獲得。",  en = "Treasures by Your Side [3/4]\n· Upgrade the Treasure in [Character] - [Treasures]. The required materials can be obtained by dismantling surplus Treasures in [Storage] - [One-Click Dismantle].",  ru = "Сокровища на твоей стороне [3/4]\n· Улучшите Сокровище в [Персонаж] - [Сокровища]. Необходимые материалы можно получить, разбирая лишние Сокровища в [Хранилище] - [Разобрать всё одним кликом].",  jp = "法宝随身【3/4】\n· 【キャラクター】-【法寶】で法寶をアップグレードせよ。必要な材料は、【所持品】-【一括分解】で余分な法寶を分解して入手できる。",  kr = "법보와 함께 [3/4]\n· [캐릭터] - [법보]에서 법보를 업그레이드하세요. 필요한 재료는 [보관함] - [일괄 분해]에서 여분의 법보를 분해하여 획득할 수 있습니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0019"] = {  key = "task_tite_desc_0019",  scn = "法宝伴身【4/4】\n· 在【角色】-【法宝】中升级法宝，所需材料，需在【储物】-【一键分解】中分解多余法宝获得。",  tcn = "法寶伴身【4/4】\n· 在【角色】-【法寶】中升級法寶，所需材料，需在【儲物】-【一鍵分解】中分解多餘法寶獲得。",  en = "Treasures by Your Side [4/4]\n· Upgrade the Treasure in [Character] - [Treasures]. The required materials can be obtained by dismantling surplus Treasures in [Storage] - [One-Click Dismantle].",  ru = "Сокровища на твоей стороне [4/4]\n· Улучшите Сокровище в [Персонаж] - [Сокровища]. Необходимые материалы можно получить, разбирая лишние Сокровища в [Хранилище] - [Разобрать всё одним кликом].",  jp = "法宝随身【4/4】\n· 【キャラクター】-【法寶】で法寶をアップグレードせよ。必要な材料は、【所持品】-【一括分解】で余分な法寶を分解して入手できる。",  kr = "법보와 함께 [4/4]\n· [캐릭터] - [법보]에서 법보를 업그레이드하세요. 필요한 재료는 [보관함] - [일괄 분해]에서 여분의 법보를 분해하여 획득할 수 있습니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0020"] = {  key = "task_tite_desc_0020",  scn = "道法传承【1/3】\n· 道法传承在【道行】中，道法随着境界逐步解锁。领悟和升级道法需[道法感悟]和[道法心得]，可去【论道】-【镇妖塔】中历练。",  tcn = "道法傳承【1/3】\n· 道法傳承在【道行】中，道法隨著境界逐步解鎖。領悟和升級道法需[道法感悟]和[道法心得]，可去【論道】-【鎮妖塔】中歷練。",  en = "Dao Art Legacy [1/3]\n· Dao Arts are found in [Cultivation] and unlock gradually as your realm advances. Comprehending and upgrading Dao Arts requires [Dao Art Enlightenment] and [Dao Art Insights]. You can obtain them by training in [Dao Discussion] - [Demon Suppression Tower].",  ru = "Наследие техник Дао [1/3]\n· Техники Дао находятся в [Культивация] и открываются постепенно по мере повышения вашей стадии. Постижение и улучшение техник Дао требует [Просветлений в техники Дао] и [Прозрений в техники Дао]. Вы можете получить их, тренируясь в [Беседа о Дао] - [Башня Усмирения Демонов].",  jp = "道法伝承【1/3】\n· 道法伝承は【道行き】にあり、道法は境界に応じて段階的に解放される。道法の悟りとアップグレードには【道法の悟り】と【道法の心得】が必要。【論道】-【鎮妖塔】での修行で入手できる。",  kr = "도법 계승 [1/3]\n· 도법 계승은 [도력]에 있으며, 도법은 경지에 따라 단계적으로 해금됩니다. 도법을 깨우치고 업그레이드하려면 [도법 돈오]와 [도법 심득]이 필요합니다. [논도] - [요괴 봉인 탑]에서 수행하여 획득할 수 있습니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0021"] = {  key = "task_tite_desc_0021",  scn = "道法传承【2/3】\n· 在【角色】-【道法】中装配道法，道法栏位随着境界逐步解锁。",  tcn = "道法傳承【2/3】\n· 在【角色】-【道法】中裝配道法，道法欄位隨著境界逐步解鎖。",  en = "Dao Art Legacy [2/3]\n· Equip Dao Arts in [Character] - [Dao Arts]. Dao Art slots unlock gradually as your realm advances.",  ru = "Наследие техник Дао [2/3]\n· Экипируйте техники Дао в [Персонаж] - [Техники Дао]. Слоты для техник Дао открываются постепенно по мере повышения вашей стадии.",  jp = "道法伝承【2/3】\n· 【キャラクター】-【道法】で道法を装備せよ。道法のスロットは境界に応じて段階的に解放される。",  kr = "도법 계승 [2/3]\n· [캐릭터] - [도법]에서 도법을 장착하세요. 도법 슬롯은 경지에 따라 단계적으로 해금됩니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0022"] = {  key = "task_tite_desc_0022",  scn = "道法传承【3/3】\n· 道法提升，需要消耗道法心得与道法感悟。闯关【镇妖塔】的层数越高，每分钟增加的[道法心得]越多。领取[道法心得]，可去【论道】-【镇妖塔】界面领取",  tcn = "道法傳承【3/3】\n· 道法提升，需要消耗道法心得與道法感悟。闖關【鎮妖塔】的層數越高，每分鐘增加的[道法心得]越多。領取[道法心得]，可去【論道】-【鎮妖塔】介面領取",  en = "Dao Art Legacy [3/3]\n· Upgrading Dao Arts consumes Dao Art Insights and Dao Art Enlightenment. The higher the floor you reach in [Demon Suppression Tower], the more [Dao Art Insights] you gain per minute. To claim [Dao Art Insights], go to the [Dao Discussion] - [Demon Suppression Tower] interface.",  ru = "Наследие техник Дао [3/3]\n· Улучшение техник Дао требует Прозрений в техники Дао и Просветлений в техники Дао. Чем выше этаж в [Башня Усмирения Демонов], тем больше [Прозрений в техники Дао] вы получаете в минуту. Чтобы получить [Прозрения в техники Дао], зайдите в интерфейс [Беседа о Дао] - [Башня Усмирения Демонов].",  jp = "道法伝承【3/3】\n· 道法の向上には道法の心得と道法の悟りを消費する。【鎮妖塔】の階層が高いほど、毎分得られる【道法の心得】が増える。【道法の心得】の受け取りは、【論道】-【鎮妖塔】画面から行う。",  kr = "도법 계승 [3/3]\n· 도법을 강화하려면 도법 심득과 도법 돈오를 소비합니다. [요괴 봉인 탑]의 층수가 높을수록 분당 획득하는 [도법 심득]이 많아집니다. [도법 심득]을 수령하려면 [논도] - [요괴 봉인 탑] 인터페이스로 이동하세요.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0023"] = {  key = "task_tite_desc_0023",  scn = "道法传承【1/2】\n· 洞天既立，可辟灵田。在【洞府】-【灵田】中栽下灵种，待其生根吐蕊，灵材药草无忧。",  tcn = "道法傳承【1/2】\n· 洞天既立，可闢靈田。在【洞府】-【靈田】中栽下靈種，待其生根吐蕊，靈材藥草無憂。",  en = "Dao Art Legacy [1/2]\n· With your abode established, you can now open a Spirit Field. Plant spirit seeds in [Abode] - [Spirit Field]. Once they take root and bloom, you will never lack spirit materials and herbs.",  ru = "Наследие техник Дао [1/2]\n· С созданием обители вы можете открыть Духовное поле. Посадите семена духовных растений в [Обитель] - [Духовное поле]. Когда они пустят корни и зацветут, у вас всегда будут духовные материалы и травы.",  jp = "道法伝承【1/2】\n· 洞天既に立てば、霊田を開ける。【洞府】-【霊田】に霊種を植え、根付き花咲くを待てば、霊材薬草に困らぬ。",  kr = "도법 계승 [1/2]\n· 동천을 세웠으니 영농지를 열 수 있습니다. [동부] - [영농지]에 영종을 심고 뿌리내려 꽃피기를 기다리면 영재와 약초가 부족하지 않습니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0024"] = {  key = "task_tite_desc_0024",  scn = "道法传承【2/2】\n· 在【洞府】-【灵田】中收获一次天品凝露草。",  tcn = "道法傳承【2/2】\n· 在【洞府】-【靈田】中收穫一次天品凝露草。",  en = "Dao Art Legacy [2/2]\n· Harvest a Heavenly-grade Dew Condensation Herb from [Abode] - [Spirit Field].",  ru = "Наследие техник Дао [2/2]\n· Соберите Траву Конденсации Росы Небесного качества на [Обитель] - [Духовное поле].",  jp = "道法伝承【2/2】\n· 【洞府】-【霊田】で天品の凝露草を一度収穫せよ。",  kr = "도법 계승 [2/2]\n· [동부] - [영농지]에서 천품 응로초를 한 번 수확하세요.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0025"] = {  key = "task_tite_desc_0025",  scn = "齐头并进【2/3】\n· 在 【洞府】-【修炼台】中选择另外的修炼方向，并突破至【练气期七层】。多余的材料，不妨炼些其它修炼方向的丹药，单修固然快，毕竟双修无短板。",  tcn = "齊頭並進【2/3】\n· 在 【洞府】-【修煉台】中選擇另外的修煉方向，並突破至【練氣期七層】。多餘的材料，不妨煉些其它修煉方向的丹藥，單修固然快，畢竟雙修無短板。",  en = "Advancing Together [2/3]\n· Select a different cultivation path in [Abode] - [Cultivation Platform] and break through to [Qi Refining Level 7]. Use excess materials to refine pills for other paths. While focusing on one path is faster, cultivating both leaves no weaknesses.",  ru = "Совместное продвижение [2/3]\n· Выберите другое направление культивации в [Обитель] - [Платформа культивации] и совершите прорыв до [7-го уровня Поглощения ци]. Используйте излишние материалы для создания пилюль для других направлений. Хотя сосредоточение на одном пути быстрее, развитие обоих не даёт слабых мест.",  jp = "共に前進【2/3】\n· 【洞府】-【修練台】で別の修煉方向を選択し、【練気期七層】まで突破せよ。余った材料で他の修煉方向の丹薬を煉るのがよい。単修も早いが、双修に短板なし。",  kr = "함께 나아가기 [2/3]\n· [동부] - [수련대]에서 다른 수행 방향을 선택하고 [연기 7층]까지 돌파하세요. 남는 재료로 다른 수행 방향의 단약을 제련해 보세요. 한 방향만 수련하는 것이 빠르지만, 두 방향 모두 수련하면 약점이 없습니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0026"] = {  key = "task_tite_desc_0026",  scn = "齐头并进【3/3】\n· 在 【洞府】-【修炼台】中选择另外的修炼方向，并突破至【练气期圆满】。多余的材料，不妨炼些其它修炼方向的丹药，单修固然快，毕竟双修无短板。",  tcn = "齊頭並進【3/3】\n· 在 【洞府】-【修煉台】中選擇另外的修煉方向，並突破至【練氣期圓滿】。多餘的材料，不妨煉些其它修煉方向的丹藥，單修固然快，畢竟雙修無短板。",  en = "Advancing Together [3/3]\n· Select a different cultivation path in [Abode] - [Cultivation Platform] and break through to [Qi Refining Perfection]. Use excess materials to refine pills for other paths. While focusing on one path is faster, cultivating both leaves no weaknesses.",  ru = "Совместное продвижение [3/3]\n· Выберите другое направление культивации в [Обитель] - [Платформа культивации] и совершите прорыв до [Совершенства Поглощения ци]. Используйте излишние материалы для создания пилюль для других направлений. Хотя сосредоточение на одном пути быстрее, развитие обоих не даёт слабых мест.",  jp = "共に前進【3/3】\n· 【洞府】-【修練台】で別の修煉方向を選択し、【練気期円満】まで突破せよ。余った材料で他の修煉方向の丹薬を煉るのがよい。単修も早いが、双修に短板なし。",  kr = "함께 나아가기 [3/3]\n· [동부] - [수련대]에서 다른 수행 방향을 선택하고 [연기 원만]까지 돌파하세요. 남는 재료로 다른 수행 방향의 단약을 제련해 보세요. 한 방향만 수련하는 것이 빠르지만, 두 방향 모두 수련하면 약점이 없습니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0027"] = {  key = "task_tite_desc_0027",  scn = "珍宝难得【1/3】\n· 在【洞府】-【炼器坊】中炼制1次上品法宝，法宝品质越高，所得属性越高，锻造的词条也越多。",  tcn = "珍寶難得【1/3】\n· 在【洞府】-【煉器坊】中煉製1次上品法寶，法寶品質越高，所得屬性越高，鍛造的詞條也越多。",  en = "Rare Treasures [1/3]\n· Refine a Superior-quality Treasure once in [Abode] - [Artifact Forge]. The higher the Treasure\'s quality, the higher its attributes and the more affixes it will have.",  ru = "Редкие сокровища [1/3]\n· Создайте одно Сокровище высшего качества в [Обитель] - [Мастерская артефактов]. Чем выше качество Сокровища, тем выше его характеристики и тем больше аффиксов оно имеет.",  jp = "珍宝希少【1/3】\n· 【洞府】-【法宝鍛造所】で上品法寶を1回錬成せよ。法寶の品質が高いほど、得られる属性が高く、鍛造されるオプションも多くなる。",  kr = "진귀한 보물 [1/3]\n· [동부] - [법보 제련방]에서 상품 법보를 1회 제련하세요. 법보의 품질이 높을수록 획득 속성이 높아지고, 제작 시 옵션도 많아집니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0028"] = {  key = "task_tite_desc_0028",  scn = "珍宝难得【2/3】\n· 在【洞府】-【炼器坊】中炼制1次极品法宝，法宝品质越高，所得属性越高，锻造的词条也越多。",  tcn = "珍寶難得【2/3】\n· 在【洞府】-【煉器坊】中煉製1次極品法寶，法寶品質越高，所得屬性越高，鍛造的詞條也越多。",  en = "Rare Treasures [2/3]\n· Refine a Supreme-quality Treasure once in [Abode] - [Artifact Forge]. The higher the Treasure\'s quality, the higher its attributes and the more affixes it will have.",  ru = "Редкие сокровища [2/3]\n· Создайте одно Сокровище превосходного качества в [Обитель] - [Мастерская артефактов]. Чем выше качество Сокровища, тем выше его характеристики и тем больше аффиксов оно имеет.",  jp = "珍宝希少【2/3】\n· 【洞府】-【法宝鍛造所】で極品法寶を1回錬成せよ。法寶の品質が高いほど、得られる属性が高く、鍛造されるオプションも多くなる。",  kr = "진귀한 보물 [2/3]\n· [동부] - [법보 제련방]에서 극품 법보를 1회 제련하세요. 법보의 품질이 높을수록 획득 속성이 높아지고, 제작 시 옵션도 많아집니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0029"] = {  key = "task_tite_desc_0029",  scn = "珍宝难得【3/3】\n· 在【洞府】-【炼器坊】中炼制1次天品法宝，法宝品质越高，所得属性越高，锻造的词条也越多。",  tcn = "珍寶難得【3/3】\n· 在【洞府】-【煉器坊】中煉製1次天品法寶，法寶品質越高，所得屬性越高，鍛造的詞條也越多。",  en = "Rare Treasures [3/3]\n· Refine a Heavenly-quality Treasure once in [Abode] - [Artifact Forge]. The higher the Treasure\'s quality, the higher its attributes and the more affixes it will have.",  ru = "Редкие сокровища [3/3]\n· Создайте одно Сокровище Небесного качества в [Обитель] - [Мастерская артефактов]. Чем выше качество Сокровища, тем выше его характеристики и тем больше аффиксов оно имеет.",  jp = "珍宝希少【3/3】\n· 【洞府】-【法宝鍛造所】で天品法寶を1回錬成せよ。法寶の品質が高いほど、得られる属性が高く、鍛造されるオプションも多くなる。",  kr = "진귀한 보물 [3/3]\n· [동부] - [법보 제련방]에서 천품 법보를 1회 제련하세요. 법보의 품질이 높을수록 획득 속성이 높아지고, 제작 시 옵션도 많아집니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0030"] = {  key = "task_tite_desc_0030",  scn = "妙丹难得【1/3】\n· 在【洞府】-【炼丹房】中炼制1次上品修为丹，丹药增加的丹毒虽一致，但品质越高，所增加的修为越多。",  tcn = "妙丹難得【1/3】\n· 在【洞府】-【煉丹房】中煉製1次上品修為丹，丹藥增加的丹毒雖一致，但品質越高，所增加的修為越多。",  en = "Rare Marvelous Pills [1/3]\n· Refine a Superior-quality Cultivation Pill once in [Abode] - [Alchemy Room]. While the pill toxicity added is the same regardless of quality, higher quality pills provide more cultivation.",  ru = "Редкие чудесные пилюли [1/3]\n· Создайте одну Пилюлю культивации высшего качества в [Обитель] - [Алхимическая комната]. Хотя добавляемая пилюльная токсичность одинакова независимо от качества, пилюли более высокого качества дают больше опыта культивации.",  jp = "妙丹希少【1/3】\n· 【洞府】-【錬丹室】で上品修為丹を1回錬成せよ。丹薬が増加する丹毒は同じでも、品質が高いほど得られる修為が増える。",  kr = "묘한 단약 [1/3]\n· [동부] - [단약 제련실]에서 상품 수행단을 1회 제련하세요. 단약이 추가하는 단독은 동일하지만, 품질이 높을수록 증가하는 수행량이 많아집니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0031"] = {  key = "task_tite_desc_0031",  scn = "妙丹难得【2/3】\n· 在【洞府】-【炼丹房】中炼制1次极品修为丹，丹药增加的丹毒虽一致，但品质越高，所增加的修为越多。",  tcn = "妙丹難得【2/3】\n· 在【洞府】-【煉丹房】中煉製1次極品修為丹，丹藥增加的丹毒雖一致，但品質越高，所增加的修為越多。",  en = "Rare Marvelous Pills [2/3]\n· Refine a Supreme-quality Cultivation Pill once in [Abode] - [Alchemy Room]. While the pill toxicity added is the same regardless of quality, higher quality pills provide more cultivation.",  ru = "Редкие чудесные пилюли [2/3]\n· Создайте одну Пилюлю культивации превосходного качества в [Обитель] - [Алхимическая комната]. Хотя добавляемая пилюльная токсичность одинакова независимо от качества, пилюли более высокого качества дают больше опыта культивации.",  jp = "妙丹希少【2/3】\n· 【洞府】-【錬丹室】で極品修為丹を1回錬成せよ。丹薬が増加する丹毒は同じでも、品質が高いほど得られる修為が増える。",  kr = "묘한 단약 [2/3]\n· [동부] - [단약 제련실]에서 극품 수행단을 1회 제련하세요. 단약이 추가하는 단독은 동일하지만, 품질이 높을수록 증가하는 수행량이 많아집니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0032"] = {  key = "task_tite_desc_0032",  scn = "妙丹难得【3/3】\n· 在【洞府】-【炼丹房】中炼制1次天品修为丹，丹药增加的丹毒虽一致，但品质越高，所增加的修为越多。",  tcn = "妙丹難得【3/3】\n· 在【洞府】-【煉丹房】中煉製1次天品修為丹，丹藥增加的丹毒雖一致，但品質越高，所增加的修為越多。",  en = "Rare Marvelous Pills [3/3]\n· Refine a Heavenly-quality Cultivation Pill once in [Abode] - [Alchemy Room]. While the pill toxicity added is the same regardless of quality, higher quality pills provide more cultivation.",  ru = "Редкие чудесные пилюли [3/3]\n· Создайте одну Пилюлю культивации Небесного качества в [Обитель] - [Алхимическая комната]. Хотя добавляемая пилюльная токсичность одинакова независимо от качества, пилюли более высокого качества дают больше опыта культивации.",  jp = "妙丹希少【3/3】\n· 【洞府】-【錬丹室】で天品修為丹を1回錬成せよ。丹薬が増加する丹毒は同じでも、品質が高いほど得られる修為が増える。",  kr = "묘한 단약 [3/3]\n· [동부] - [단약 제련실]에서 천품 수행단을 1회 제련하세요. 단약이 추가하는 단독은 동일하지만, 품질이 높을수록 증가하는 수행량이 많아집니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0033"] = {  key = "task_tite_desc_0033",  scn = "宝阁寻珍【1/2】\n· 在【宝阁】中购买1次商品。宝阁珍宝众多，不妨看看，或可购得极品道具。",  tcn = "寶閣尋珍【1/2】\n· 在【寶閣】中購買1次商品。寶閣珍寶眾多，不妨看看，或可購得極品道具。",  en = "Treasure Pavilion Hunt [1/2]\n· Purchase an item from the [Treasure Pavilion] once. The Treasure Pavilion is filled with rare items. Take a look—you might just find a Supreme-grade treasure.",  ru = "Поиск сокровищ в Сокровищнице [1/2]\n· Купите один предмет в [Сокровищница]. Сокровищница полна редких предметов. Взгляните — возможно, вы найдёте сокровище превосходного качества.",  jp = "宝閣で珍品探し【1/2】\n· 【宝閣】で商品を1回購入せよ。宝閣には多くの珍宝がある。覗いてみれば、極品の道具を購入できるかもしれない。",  kr = "보물 전당의 진귀한 보물 [1/2]\n· [보물 전당]에서 상품을 1회 구매하세요. 보물 전당에는 진귀한 보물이 많습니다. 한번 둘러보면 극품 아이템을 구할 수도 있습니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["task_tite_desc_0034"] = {  key = "task_tite_desc_0034",  scn = "宝阁寻珍【2/2】\n· 在【宝阁】中刷新1次商品。若不满意商品，耗费些许灵石，刷新即可。不过刷新的越多，耗费灵石越多。",  tcn = "寶閣尋珍【2/2】\n· 在【寶閣】中刷新1次商品。若不滿意商品，耗費些許靈石，刷新即可。不過刷新的越多，耗費靈石越多。",  en = "Treasure Pavilion Hunt [2/2]\n· Refresh the [Treasure Pavilion] once. If you\'re not satisfied with the items, spend a few Spirit Stones to refresh. However, the cost increases with each refresh.",  ru = "Поиск сокровищ в Сокровищнице [2/2]\n· Обновите [Сокровищницу] один раз. Если вы не удовлетворены товарами, потратьте немного Духовных камней на обновление. Однако стоимость увеличивается с каждым обновлением.",  jp = "宝閣で珍品探し【2/2】\n· 【宝閣】で商品を1回更新せよ。商品に満足できなければ、若干の霊石を払って更新すればよい。ただし、更新するほど必要な霊石が増える。",  kr = "보물 전당의 진귀한 보물 [2/2]\n· [보물 전당]에서 상품을 1회 새로 고침하세요. 상품이 마음에 들지 않으면 영석을 소모하여 새로 고침할 수 있습니다. 단, 새로 고침할수록 소모 영석이 증가합니다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
