data["talk_name_00003"] = {  key = "talk_name_00003",  scn = "<color=#009100>护道者</color>",  tcn = "<color=#009100>護道者</color>",  en = "<color=#009100>Dao Protector</color>",  ru = "<color=#009100>Хранитель Дао</color>",  jp = "<color=#009100>道護り</color>",  kr = "<color=#009100>도호자</color>",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00001"] = {  key = "talk_name_dialogue_00001",  scn = "“求道者？来晚了。”",  tcn = "“求道者？來晚了。”",  en = "“A seeker of the Dao? You are too late.”",  ru = "«Ищущий Дао? Ты опоздал.»",  jp = "「求道者？遅すぎた。」",  kr = "“도를 구하는 자? 너무 늦었소.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00002"] = {  key = "talk_name_dialogue_00002",  scn = "“人族已灭。妖兽横行，我都受困如此。”",  tcn = "“人族已滅。妖獸橫行，我都受困如此。”",  en = "“The human race is extinct. Demon beasts run rampant, and even I am trapped like this.”",  ru = "«Человеческая раса истреблена. Демонические звери бесчинствуют, и даже я оказался в ловушке».",  jp = "「人族は滅びた。妖兽が横行し、私もこうして囚われている。」",  kr = "“인족은 멸망했소. 요수가 횡행하여, 나조차 이렇게 갇혀 있소.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00003"] = {  key = "talk_name_dialogue_00003",  scn = "“救不了，除非……斩尽妖兽。”",  tcn = "“救不了，除非……斬盡妖獸。”",  en = "“There is no saving it, unless… you exterminate every last demon beast.”",  ru = "«Спасти невозможно, если только… не истребить всех демонических зверей».",  jp = "「救えない、もし…全ての妖兽を斬り尽くすのでなければ。」",  kr = "“구할 수 없소… 모든 요수를 베어 없애지 않는 한.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00004"] = {  key = "talk_name_dialogue_00004",  scn = "“拿去，好好活着，<color=#005757>洞府</color>可随身修行。<color=#AE8F00>灵明飞剑</color>可御空。”",  tcn = "“拿去，好好活著，<color=#005757>洞府</color>可隨身修行。<color=#AE8F00>靈明飛劍</color>可御空。”",  en = "“Take this, stay alive. The [<color=#005757>Abode</color>] can be carried with you for cultivation. The [<color=#AE8F00>Luminous Flying Sword</color>] allows you to soar through the skies.”",  ru = "«Возьми это, останься в живых. [<color=#005757>Обитель</color>] можно носить с собой для культивации. [<color=#AE8F00>Светозарный летающий меч</color>] позволяет парить в небесах».",  jp = "「受け取れ、生き延びよ。【<color=#005757>洞府</color>】は携帯して修行できる。<color=#AE8F00>霊明飛剣</color>は空中を飛べる。」",  kr = "“받아라, 잘 살아가거라. [<color=#005757>동부</color>]는 휴대하며 수련할 수 있소. [<color=#AE8F00>영명비검</color>]은 허공을 날게 해주리라.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00005"] = {  key = "talk_name_dialogue_00005",  scn = "“先去洞府修炼。<color=#00CCFF>法修</color>凝真元，御群敌。<color=#EA7500>体修</color>锻气血，破强敌。”",  tcn = "“先去洞府修煉。<color=#00CCFF>法修</color>凝真元，御群敵。<color=#EA7500>體修</color>鍛氣血，破強敵。”",  en = "“First, go to the Abode and cultivate. [<color=#00CCFF>Spell Cultivators</color>] condense True Energy and handle groups of enemies. [<color=#EA7500>Body Cultivators</color>] temper their vitality and break through powerful foes.”",  ru = "«Сначала иди в Обитель и культивируй. [<color=#00CCFF>Маги</color>] конденсируют Истинную энергию и сражаются с группами врагов. [<color=#EA7500>Телесные культиваторы</color>] закаляют жизненную силу и сокрушают сильных врагов».",  jp = "「まず洞府で修行せよ。<color=#00CCFF>法修</color>は真元を凝り、群敵を御す。<color=#EA7500>体修</color>は気血を鍛え、強敵を破る。」",  kr = "“먼저 동부로 가서 수련하시오. <color=#00CCFF>법수</color>는 진원을 응결하여 다수의 적을 상대하고, <color=#EA7500>체수</color>는 기혈을 단련하여 강적을 깨부수오.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00006"] = {  key = "talk_name_dialogue_00006",  scn = "“能走到什么地步，就看你的能耐了。”",  tcn = "“能走到什麼地步，就看你的能耐了。”",  en = "“How far you can go depends entirely on your own ability.”",  ru = "«Насколько далеко ты сможешь зайти, зависит исключительно от твоих способностей».",  jp = "「どこまで行けるかは、お前の腕次第だ。」",  kr = "“어디까지 갈 수 있을지는 전적으로 그대의 능력에 달렸소.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00007"] = {  key = "talk_name_dialogue_00007",  scn = "“不错，这么快便已突破。”",  tcn = "“不錯，這麼快便已突破。”",  en = "“Not bad, you’ve already broken through so quickly.”",  ru = "«Неплохо, ты уже совершил прорыв так быстро».",  jp = "「いいぞ、もう突破したのか。」",  kr = "“좋군, 벌써 돌파했소.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00008"] = {  key = "talk_name_dialogue_00008",  scn = "“苦修终遇瓶颈。”",  tcn = "“苦修終遇瓶頸。”",  en = "“Hard cultivation eventually hits a bottleneck.”",  ru = "«Упорная культивация в конце концов упирается в бутылочное горлышко».",  jp = "「苦修もいずれ瓶頸に遭う。」",  kr = "“고행 끝에 결국 병목을 만났소.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00009"] = {  key = "talk_name_dialogue_00009",  scn = "“不如斩杀妖兽炼丹。”",  tcn = "“不如斬殺妖獸煉丹。”",  en = "“Better to slay demon beasts and refine pills.”",  ru = "«Лучше убивать демонических зверей и создавать пилюли».",  jp = "「妖兽を斬って丹を煉るがいい。」",  kr = "“차라리 요수를 베어 단약을 제련하는 게 낫소.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00010"] = {  key = "talk_name_dialogue_00010",  scn = "“洞府有<color=#005757>炼丹室</color>。查看<color=#6A6AFF>丹方</color>所需妖兽材料与灵药。”",  tcn = "“洞府有<color=#005757>煉丹室</color>。查看<color=#6A6AFF>丹方</color>所需妖獸材料與靈藥。”",  en = "“The Abode has an [<color=#005757>Alchemy Room</color>]. Check the [<color=#6A6AFF>recipes</color>] for required demon beast materials and spirit herbs.”",  ru = "«В Обители есть [<color=#005757>Алхимическая комната</color>]. Проверь [<color=#6A6AFF>рецепты</color>] на предмет необходимых материалов демонических зверей и духовных трав».",  jp = "「洞府には<color=#005757>錬丹室</color>がある。<color=#6A6AFF>丹方</color>に必要な妖兽の素材と霊薬を確認せよ。」",  kr = "“동부에는 [<color=#005757>단약 제련실</color>]이 있소. [<color=#6A6AFF>단방</color>]에 필요한 요수 재료와 영약을 살펴보시오.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00011"] = {  key = "talk_name_dialogue_00011",  scn = "“材料<color=#6A6AFF>品质愈佳</color>，成丹<color=#6A6AFF>概率便愈高</color>。”",  tcn = "“材料<color=#6A6AFF>品質愈佳</color>，成丹<color=#6A6AFF>概率便愈高</color>。”",  en = "“The <color=#6A6AFF>higher the quality of the materials</color>, the <color=#6A6AFF>greater the chance</color> of successfully refining the pill.”",  ru = "«<color=#6A6AFF>Чем выше качество материалов</color>, тем <color=#6A6AFF>выше вероятность</color> успешного создания пилюли».",  jp = "「材料の<color=#6A6AFF>品質が高いほど</color>、成丹の<color=#6A6AFF>確率も高まる</color>。」",  kr = "“재료의 <color=#6A6AFF>품질이 좋을수록</color>, 단약이 만들어질 <color=#6A6AFF>확률도 높아지네</color>.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00012"] = {  key = "talk_name_dialogue_00012",  scn = "“好，既入我太乙玄门，往后我便是你的——<color=#009100>护道者</color>。”",  tcn = "“好，既入我太乙玄門，往後我便是你的——<color=#009100>護道者</color>。”",  en = "“Good. Now that you have entered my Taiyi Xuan Sect, from now on, I will be your — <color=#009100>Dao Protector</color>.”",  ru = "«Хорошо. Раз ты вступил в мою секту Тайи Сюань, отныне я буду твоим — <color=#009100>Хранителем Дао</color>».",  jp = "「よし。我が太乙玄門に入ったからには、これより私はお前の——<color=#009100>道護り</color>となる。」",  kr = "“좋소. 이제 내 태을현문에 들었으니, 이제부터 내가 그대의 — <color=#009100>도호자</color>가 되리라.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00013"] = {  key = "talk_name_dialogue_00013",  scn = "“此有二礼：\n 一为【<color=#005757>洞府</color>】，内里自成乾坤，可随身携带，供你吐纳修行\n二为[<color=#AE8F00>灵明飞剑</color>]，此剑念动即行，即便无修为，也可护你周全，带你云游九天。”",  tcn = "“此有二禮：\n 一為【<color=#005757>洞府</color>】，內裡自成乾坤，可隨身攜帶，供你吐納修行\n二為[<color=#AE8F00>靈明飛劍</color>]，此劍念動即行，即便無修為，也可護你周全，帶你雲遊九天。”",  en = "“I have two gifts for you:\n The first is the [<color=#005757>Abode</color>], a space that contains its own universe. You can carry it with you and use it for cultivation.\n The second is the [<color=#AE8F00>Luminous Flying Sword</color>]. This sword moves at your thought. Even without cultivation, it can protect you and carry you across the nine heavens.”",  ru = "«У меня для тебя два дара:\n Первый — [<color=#005757>Обитель</color>], пространство, содержащее собственную вселенную. Ты можешь носить её с собой и использовать для культивации.\n Второй — [<color=#AE8F00>Светозарный летающий меч</color>]. Этот меч движется по твоей мысли. Даже без культивации он сможет защитить тебя и вознести по девяти небесам».",  jp = "「二つの贈り物がある：\n 一つは【<color=#005757>洞府</color>】、内部に独自の宇宙を内包し、携帯して修行に使える。\n 二つは[<color=#AE8F00>霊明飛剣</color>]、この剣は思念で動き、たとえ修為がなくともお前を守り、九天を遊行させることができる。」",  kr = "“두 가지 예물이 있소:\n 첫째는 [<color=#005757>동부</color>]로, 내부에 자체 천지를 이루어 휴대하며 수련할 수 있소.\n 둘째는 [<color=#AE8F00>영명비검</color>]으로, 이 검은 생각만으로도 움직이며, 수행이 없더라도 그대를 지키고 구천을 유람하게 할 것이오.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00014"] = {  key = "talk_name_dialogue_00014",  scn = "“你且先去开启【<color=#005757>洞府</color>】，褪去凡躯，方能正式踏入道途。”",  tcn = "“你且先去開啟【<color=#005757>洞府</color>】，褪去凡軀，方能正式踏入道途。”",  en = "“First, go and open the [<color=#005757>Abode</color>] to shed your mortal form, then you can formally step onto the path of Dao.”",  ru = "«Сначала открой [<color=#005757>Обитель</color>], чтобы сбросить смертную оболочку, и только затем сможешь официально вступить на путь Дао».",  jp = "「まず【<color=#005757>洞府</color>】を開き、凡躯を脱ぎ捨てよ。そうして初めて正式に道途へと踏み出せる。」",  kr = "“먼저 [<color=#005757>동부</color>]를 열어 범부의 몸을 벗어버려야, 비로소 도의 길에 공식적으로 들어설 수 있소.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00015"] = {  key = "talk_name_dialogue_00015",  scn = "“修炼台中可选两种修炼之法：一为<color=#00CCFF>法修</color>，二为<color=#EA7500>体修</color>。”",  tcn = "“修煉台中可選兩種修煉之法：一為<color=#00CCFF>法修</color>，二為<color=#EA7500>體修</color>。”",  en = "“In the Cultivation Platform, you can choose between two cultivation paths: one is <color=#00CCFF>Spell Cultivation</color>, the other is <color=#EA7500>Body Cultivation</color>.”",  ru = "«На платформе культивации ты можешь выбрать один из двух путей: первый — <color=#00CCFF>Магический путь</color>, второй — <color=#EA7500>Путь тела</color>».",  jp = "「修練台では二つの修煉法が選べる。一つは<color=#00CCFF>法修</color>、もう一つは<color=#EA7500>体修</color>だ。」",  kr = "“수련대에서 두 가지 수행법 중 하나를 선택할 수 있소. 하나는 <color=#00CCFF>법수</color>요, 다른 하나는 <color=#EA7500>체수</color>라네.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00016"] = {  key = "talk_name_dialogue_00016",  scn = "“<color=#00CCFF>法修</color>引天地灵气入体，凝练<color=#00CCFF>真元</color>。\n 你可以理解为蓝量，此法真元雄厚，<color=#00CCFF>善御群敌</color>；\n <color=#EA7500>体修</color>千锤百炼血肉之躯，<color=#EA7500>气血</color>如龙。\n 你可以理解为血量，此法<color=#EA7500>单点破敌</color>，爆发极强。”",  tcn = "“<color=#00CCFF>法修</color>引天地靈氣入體，凝練<color=#00CCFF>真元</color>。\n 你可以理解為藍量，此法真元雄厚，<color=#00CCFF>善御群敵</color>；\n <color=#EA7500>體修</color>千錘百煉血肉之軀，<color=#EA7500>氣血</color>如龍。\n 你可以理解為血量，此法<color=#EA7500>單點破敵</color>，爆發極強。”",  en = "“<color=#00CCFF>Spell Cultivators</color> draw the spiritual energy of heaven and earth into their bodies to refine <color=#00CCFF>True Energy</color>.\n Think of it as mana. This path grants vast reserves of True Energy, making them <color=#00CCFF>skilled at handling multiple foes</color>.\n <color=#EA7500>Body Cultivators</color> temper their flesh and blood through endless training, their <color=#EA7500>vitality</color> like a dragon’s.\n Think of it as health. This path excels at <color=#EA7500>single-target destruction</color> with explosive power.”",  ru = "«<color=#00CCFF>Маги</color> впитывают духовную энергию неба и земли, конденсируя <color=#00CCFF>Истинную энергию</color>.\n Можешь считать это маной. Этот путь даёт огромные резервы энергии, позволяя <color=#00CCFF>эффективно сражаться с толпами врагов</color>.\n <color=#EA7500>Телесные культиваторы</color> закаляют свою плоть и кровь бесчисленными тренировками, их <color=#EA7500>жизненная сила</color> подобна силе дракона.\n Можешь считать это здоровьем. Этот путь специализируется на <color=#EA7500>уничтожении одиночных целей</color> с огромной мощью».",  jp = "「<color=#00CCFF>法修</color>は天地の霊気を体内に引き込み、<color=#00CCFF>真元</color>を凝練する。\n これはマナのようなものだ。この道は真元が厚く、<color=#00CCFF>多数の敵を御するのが得意</color>。\n <color=#EA7500>体修</color>は血肉の体を幾度も鍛え上げ、<color=#EA7500>気血</color>は龍の如し。\n これはヒットポイントのようなものだ。この道は<color=#EA7500>一点突破で敵を破る</color>ことに優れ、爆発力が極めて高い。」",  kr = "“<color=#00CCFF>법수</color>는 천지 영기를 몸에 끌어들여 <color=#00CCFF>진원</color>을 응결하네.\n 이는 마나와 같다네. 이 법은 진원이 풍부하여 <color=#00CCFF>다수의 적을 상대하는 데 능하며</color>,\n <color=#EA7500>체수</color>는 천태만련으로 혈육의 몸을 단련하여 <color=#EA7500>기혈</color>이 용과 같다네.\n 이는 체력과 같다네. 이 법은 <color=#EA7500>단일 적 돌파에 특화</color>되어 폭발력이 매우 강하다네.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00017"] = {  key = "talk_name_dialogue_00017",  scn = "“日后若觉不合，亦可<color=#6A6AFF>随时转修</color>。大道三千，终将殊途同归。”",  tcn = "“日後若覺不合，亦可<color=#6A6AFF>隨時轉修</color>。大道三千，終將殊途同歸。”",  en = "“If you find it unsuitable later, you can <color=#6A6AFF>switch paths at any time</color>. Among the three thousand great Daos, all roads eventually lead to the same destination.”",  ru = "«Если позже поймёшь, что путь не подходит, ты можешь <color=#6A6AFF>сменить его в любое время</color>. Среди трёх тысяч великих Дао, все пути в итоге ведут к единой цели».",  jp = "「後で合わないと感じたら、<color=#6A6AFF>いつでも転修</color>できる。大道三千、結局は同じ所へと至る。」",  kr = "“훗날 맞지 않는다고 느껴지면 <color=#6A6AFF>언제든지 전수</color>할 수 있소. 대도 삼천, 결국 모두 같은 곳으로 돌아가니라.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00018"] = {  key = "talk_name_dialogue_00018",  scn = "“于【<color=#005757>洞府</color>】中开辟【<color=#005757>丹室</color>】，以妖兽材料，辅以灵药，便可炼丹助益修行。”",  tcn = "“於【<color=#005757>洞府</color>】中開闢【<color=#005757>丹室</color>】，以妖獸材料，輔以靈藥，便可煉丹助益修行。”",  en = "“Open an [<color=#005757>Alchemy Room</color>] within the [<color=#005757>Abode</color>]. Using demon beast materials and spirit herbs, you can refine pills to aid your cultivation.”",  ru = "«Открой [<color=#005757>Алхимическую комнату</color>] внутри [<color=#005757>Обители</color>]. Используя материалы демонических зверей и духовные травы, ты сможешь создавать пилюли для помощи в культивации».",  jp = "「【<color=#005757>洞府</color>】の中に【<color=#005757>丹室</color>】を開き、妖兽の素材と霊薬を用いれば、丹薬を錬成して修行を助けることができる。」",  kr = "“[<color=#005757>동부</color>] 안에 [<color=#005757>단실</color>]을 열어, 요수 재료와 영약을 더하면 단약을 제련하여 수행에 도움을 줄 수 있소.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00019"] = {  key = "talk_name_dialogue_00019",  scn = "“选好<color=#6A6AFF>丹方</color>后，自行斟酌取材——材料<color=#6A6AFF>品质愈佳</color>，成丹<color=#6A6AFF>概率便愈高</color>。”",  tcn = "“選好<color=#6A6AFF>丹方</color>後，自行斟酌取材——材料<color=#6A6AFF>品質愈佳</color>，成丹<color=#6A6AFF>概率便愈高</color>。”",  en = "“After selecting the <color=#6A6AFF>recipe</color>, carefully choose your materials — the <color=#6A6AFF>higher the quality of the materials</color>, the <color=#6A6AFF>greater the chance</color> of successfully refining the pill.”",  ru = "«Выбрав <color=#6A6AFF>рецепт</color>, тщательно подбирай материалы — <color=#6A6AFF>чем выше качество материалов</color>, тем <color=#6A6AFF>выше вероятность</color> успешного создания пилюли».",  jp = "「<color=#6A6AFF>丹方</color>を選んだら、自ら材料を検討せよ。材料の<color=#6A6AFF>品質が高いほど</color>、成丹の<color=#6A6AFF>確率も高まる</color>。」",  kr = "“<color=#6A6AFF>단방</color>을 선택한 후, 스스로 재료를 가려 쓰게 — 재료의 <color=#6A6AFF>품질이 좋을수록</color>, 단약이 만들어질 <color=#6A6AFF>확률도 높아지네</color>.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00020"] = {  key = "talk_name_dialogue_00020",  scn = "“炼器同炼丹。材质愈珍，法宝愈强。”",  tcn = "“煉器同煉丹。材質愈珍，法寶愈強。”",  en = "“Artifact forging is like alchemy. The rarer the materials, the stronger the treasure.”",  ru = "«Создание артефактов подобно алхимии. Чем реже материалы, тем сильнее сокровище».",  jp = "「鍛冶は錬丹と同じ。材質が珍しいほど、法寶は強くなる。」",  kr = "“제련은 단약 제련과 같소. 재질이 진귀할수록 법보는 강해지오.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00021"] = {  key = "talk_name_dialogue_00021",  scn = "“法宝于【<color=#005757>角色</color>】面板佩戴。”",  tcn = "“法寶於【<color=#005757>角色</color>】面板佩戴。”",  en = "“Equip treasures in the [<color=#005757>Character</color>] panel.”",  ru = "«Экипируйте сокровища в панели [<color=#005757>Персонаж</color>]».",  jp = "「法寶は【<color=#005757>キャラクター</color>】パネルで装備する。」",  kr = "“법보는 [<color=#005757>캐릭터</color>] 패널에서 장착하시오.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00022"] = {  key = "talk_name_dialogue_00022",  scn = "“多余法宝在【<color=#005757>储物</color>】分解得<color=#6A6AFF>养器灵韵</color>，可升级法宝。”",  tcn = "“多餘法寶在【<color=#005757>儲物</color>】分解得<color=#6A6AFF>養器靈韻</color>，可升級法寶。”",  en = "“Dismantle extra treasures in [<color=#005757>Storage</color>] to obtain [<color=#6A6AFF>Treasure Nurturing Spirit</color>], which can be used to upgrade treasures.”",  ru = "«Разберите лишние сокровища в [<color=#005757>Хранилище</color>], чтобы получить [<color=#6A6AFF>Дух взращивания сокровищ</color>], который можно использовать для улучшения сокровищ».",  jp = "「余分な法寶は【<color=#005757>所持品</color>】で分解して<color=#6A6AFF>養器霊韻</color>を得る。法寶のアップグレードに使える。」",  kr = "“여분의 법보는 [<color=#005757>보관함</color>]에서 분해하여 <color=#6A6AFF>양기 영운</color>을 얻을 수 있으며, 이는 법보 업그레이드에 사용되오.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00023"] = {  key = "talk_name_dialogue_00023",  scn = "“法宝售价高。缺灵石？炼几件去换。”",  tcn = "“法寶售價高。缺靈石？煉幾件去換。”",  en = "“Treasures sell for a high price. Short on spirit stones? Forge a few to exchange.”",  ru = "«Сокровища продаются по высокой цене. Не хватает духовных камней? Создайте несколько для обмена».",  jp = "「法寶の売価は高い。霊石が足りない？何個か作って換金せよ。」",  kr = "“법보 판매 가격이 높소. 영석이 부족하오? 몇 개 제련하여 바꾸시오.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00024"] = {  key = "talk_name_dialogue_00024",  scn = "“传你本门<color=#6A6AFF>道法</color>，于【<color=#005757>道行</color>】领悟。此后，我为护道者。”",  tcn = "“傳你本門<color=#6A6AFF>道法</color>，於【<color=#005757>道行</color>】領悟。此後，我為護道者。”",  en = "“I pass on to you our sect’s [<color=#6A6AFF>Dao Arts</color>]. Comprehend them in [<color=#005757>Cultivation</color>]. From now on, I am your Dao Protector.”",  ru = "«Я передаю тебе [<color=#6A6AFF>Техники Дао</color>] нашей секты. Постигай их в [<color=#005757>Культивация</color>]. Отныне я — твой Хранитель Дао».",  jp = "「我が門の<color=#6A6AFF>道法</color>を伝える。【<color=#005757>道行き</color>】で悟れ。以降、我はお前の道護りとなる。」",  kr = "“내가 그대에게 본문의 <color=#6A6AFF>도법</color>을 전하노니, [<color=#005757>도력</color>]에서 깨우치시오. 이제부터 내가 그대의 도호자라네.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00025"] = {  key = "talk_name_dialogue_00025",  scn = "“道法随<color=#6A6AFF>境界</color>显现。防好高骛远。”",  tcn = "“道法隨<color=#6A6AFF>境界</color>顯現。防好高騖遠。”",  en = "“Dao Arts appear as your [<color=#6A6AFF>realm</color> advances. This is to prevent you from aiming too high too soon.”",  ru = "«Техники Дао появляются по мере повышения твоей [<color=#6A6AFF>стадии</color>]. Это чтобы ты не стремился к слишком высокому».",  jp = "「道法は<color=#6A6AFF>境界</color>に応じて現れる。高みに急ぎすぎるな。」",  kr = "“도법은 <color=#6A6AFF>경지</color>에 따라 나타나오. 지나치게 높은 곳만 보는 것을 막기 위함이라네.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00026"] = {  key = "talk_name_dialogue_00026",  scn = "“借天道权限，铸【<color=#005757>镇妖塔</color>】。塔中为妖兽幻影。”",  tcn = "“借天道權限，鑄【<color=#005757>鎮妖塔</color>】。塔中為妖獸幻影。”",  en = "“Borrowing the authority of the Heavenly Dao, I have forged the [<color=#005757>Demon Suppression Tower</color>]. Within the tower are phantoms of demon beasts.”",  ru = "«Используя полномочия Небесного Дао, я создал [<color=#005757>Башню Усмирения Демонов</color>]. В башне находятся фантомы демонических зверей».",  jp = "「天道の権限を借りて、【<color=#005757>鎮妖塔</color>】を鋳造した。塔の中は妖兽の幻影である。」",  kr = "“천도의 권한을 빌려 [<color=#005757>요괴 봉인 탑</color>]을 주조하였소. 탑 안은 요수의 환영이라네.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00027"] = {  key = "talk_name_dialogue_00027",  scn = "“精进道法，去【<color=#005757>论道</color>】-【<color=#005757>镇妖塔</color>】。斩幻影得<color=#6A6AFF>心得</color>，提升道法。”",  tcn = "“精進道法，去【<color=#005757>論道</color>】-【<color=#005757>鎮妖塔</color>】。斬幻影得<color=#6A6AFF>心得</color>，提升道法。”",  en = "“To improve your Dao Arts, go to [<color=#005757>Dao Discussion</color>] - [<color=#005757>Demon Suppression Tower</color>]. Slay the phantoms to gain [<color=#6A6AFF>insights</color>] and elevate your Dao Arts.”",  ru = "«Чтобы улучшить свои Техники Дао, иди в [<color=#005757>Беседа о Дао</color>] - [<color=#005757>Башня Усмирения Демонов</color>]. Убивай фантомов, чтобы получить [<color=#6A6AFF>озарения</color>] и повысить уровень Техник Дао».",  jp = "「道法を磨くには、【<color=#005757>論道</color>】-【<color=#005757>鎮妖塔</color>】へ行け。幻影を斬り<color=#6A6AFF>心得</color>を得て、道法を高めよ。」",  kr = "“도법을 정진하려면 [<color=#005757>논도</color>] - [<color=#005757>요괴 봉인 탑</color>]으로 가시오. 환영을 베어 <color=#6A6AFF>심득</color>을 얻고 도법을 높이시오.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00028"] = {  key = "talk_name_dialogue_00028",  scn = "“【<color=#005757>洞府</color>】辟<color=#005757>灵田</color>，种[<color=#6A6AFF>灵药</color>][<color=#6A6AFF>灵材</color>]。”",  tcn = "“【<color=#005757>洞府</color>】辟<color=#005757>靈田</color>，種[<color=#6A6AFF>靈藥</color>][<color=#6A6AFF>靈材</color>]。”",  en = "“Open a [<color=#005757>Spirit Field</color>] in your [<color=#005757>Abode</color>] to plant [<color=#6A6AFF>spirit herbs</color>] and [<color=#6A6AFF>spirit materials</color>].”",  ru = "«Открой [<color=#005757>Духовное поле</color>] в своей [<color=#005757>Обители</color>], чтобы выращивать [<color=#6A6AFF>духовные травы</color>] и [<color=#6A6AFF>духовные материалы</color>]».",  jp = "「【<color=#005757>洞府</color>】に<color=#005757>霊田</color>を開き、[<color=#6A6AFF>霊薬</color>][<color=#6A6AFF>霊材</color>]を育てよ。」",  kr = "“[<color=#005757>동부</color>]에 [<color=#005757>영농지</color>]를 열어 [<color=#6A6AFF>영약</color>]과 [<color=#6A6AFF>영재</color>]를 심으시오.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["talk_name_dialogue_00029"] = {  key = "talk_name_dialogue_00029",  scn = "“[<color=#6A6AFF>种子</color>]于【<color=#005757>宝阁</color>】购。”",  tcn = "“[<color=#6A6AFF>種子</color>]於【<color=#005757>寶閣</color>】購。”",  en = "“[<color=#6A6AFF>Seeds</color>] can be purchased at the [<color=#005757>Treasure Pavilion</color>].”",  ru = "«[<color=#6A6AFF>Семена</color>] можно купить в [<color=#005757>Сокровищнице</color>]».",  jp = "「[<color=#6A6AFF>種</color>]は【<color=#005757>宝閣</color>】で購入せよ。」",  kr = "“[<color=#6A6AFF>씨앗</color>]은 [<color=#005757>보물 전당</color>]에서 구매하시오.”",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
