data["item_desc_200436"] = {  key = "item_desc_200436",  scn = "以地脉中各类金属为食，命牙天生带有破法与腐金道纹",  tcn = "以地脈中各類金屬為食，命牙天生帶有破法與腐金道紋",  en = "Feeds on various metals in earth veins. Life fangs are innately marked with spell-breaking and metal-corroding Dao patterns.",  ru = "Питается различными металлами в земных жилах. Клыки жизни отмечены узорами Дао, разрушающими заклинания и разъедающими металл.",  jp = "地脈中の各類金屬を食とす。命牙天生に破法と腐金の道紋を帶ぶ。",  kr = "지맥 중 각종 금속을 먹이로 함. 명아는 타고난 파법과 부금 도문을 지님.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
