data["item_desc_300000"] = {  key = "item_desc_300000",  scn = "炼制练气期丹药失败时产生的废丹，与灵兽产物混合是不错的肥料。",  tcn = "煉製練氣期丹藥失敗時產生的廢丹，與靈獸產物混合是不錯的肥料。",  en = "Waste pills produced when refining Qi Refining stage pills fail. When mixed with spirit beast byproducts, they make excellent fertilizer.",  ru = "Бракованные пилюли, полученные при неудачном изготовлении пилюль стадии Закаливания Ци. В смеси с продуктами духовных зверей служат отличным удобрением.",  jp = "練気期の丹薬の錬成に失敗した際に生じる廃丹。霊獣の産物と混ぜると良い肥料になる。",  kr = "연하기 단약 제련 실패 시 생성되는 폐단. 영수 산물과 혼합하면 훌륭한 비료가 된다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["item_desc_300001"] = {  key = "item_desc_300001",  scn = "提炼天地灵气，化为精纯法力，是法修增加修为的必备丹药，服用后会增加1点丹毒。",  tcn = "提煉天地靈氣，化為精純法力，是法修增加修為的必備丹藥，服用後會增加1點丹毒。",  en = "Refines the spiritual energy of heaven and earth into pure magical power. An essential pill for Spell Cultivators to increase cultivation. Increases Pill Toxicity by 1 point when taken.",  ru = "Очищает духовную энергию неба и земли, превращая в чистую магическую силу. Незаменимая пилюля для увеличения культивации мага. При приёме увеличивает Пилюльную токсичность на 1 пункт.",  jp = "天地の霊気を精製し、精純な法力に変える。法修が修為を増やすための必須丹薬。服用後、丹毒が1ポイント増加する。",  kr = "천지 영기를 정제하여 정순한 법력으로 변화시킨다. 법수가 수행을 증가시키는 필수 단약. 복용 시 단독이 1포인트 증가한다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["item_desc_300007"] = {  key = "item_desc_300007",  scn = "以狂暴气血之力熬炼筋骨皮膜，是体修增加气血的必备丹药，服用后会增加1点丹毒。",  tcn = "以狂暴氣血之力熬煉筋骨皮膜，是體修增加氣血的必備丹藥，服用後會增加1點丹毒。",  en = "Uses fierce vitality power to temper sinews, bones, and flesh. An essential pill for Body Cultivators to increase vitality. Increases Pill Toxicity by 1 point when taken.",  ru = "Использует яростную силу жизненной энергии для закалки сухожилий, костей и плоти. Незаменимая пилюля для увеличения жизненной силы тела. При приёме увеличивает Пилюльную токсичность на 1 пункт.",  jp = "狂暴な気血の力を以て筋骨皮膜を錬る。体修が気血を増やすための必須丹薬。服用後、丹毒が1ポイント増加する。",  kr = "광폭한 기혈의 힘으로 근골과 피막을 단련한다. 체수가 기혈을 증가시키는 필수 단약. 복용 시 단독이 1포인트 증가한다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["item_desc_300013"] = {  key = "item_desc_300013",  scn = "丹气如剑意，温养经脉与本命剑元，是剑修增加修为的必备丹药。",  tcn = "丹氣如劍意，溫養經脈與本命劍元，是劍修增加修為的必備丹藥。",  en = "Pill\'s energy carries sword intent, gently nourishing meridians and the life-bound sword essence. An essential pill for Sword Cultivators to increase cultivation.",  ru = "Энергия пилюли несёт намерение меча, мягко питая меридианы и жизненно важную сущность меча. Незаменимая пилюля для увеличения культивации мечника.",  jp = "丹気は剣意の如く、経脈と本命の剣元を温養する。剣修が修為を増やすための必須丹薬。",  kr = "단기가 검의와 같아 경맥과 본명의 검원을 온양한다. 검수가 수행을 증가시키는 필수 단약.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["item_desc_300019"] = {  key = "item_desc_300019",  scn = "凝聚至阴魔气，化天地浊气为精纯魔元，是真魔增加修为的必备丹药。",  tcn = "凝聚至陰魔氣，化天地濁氣為精純魔元，是真魔增加修為的必備丹藥。",  en = "Condenses ultimate yin demonic qi, transforming the world\'s turbid qi into pure demonic essence. An essential pill for True Demons to increase cultivation.",  ru = "Конденсирует предельную инь демоническую ци, превращая мутную ци мира в чистую демоническую сущность. Незаменимая пилюля для увеличения культивации Истинного Демона.",  jp = "至陰の魔気を凝集し、天地の濁気を精純な魔元に変える。真魔が修為を増やすための必須丹薬。",  kr = "지음의 마기를 응집하고 천지의 탁기를 정순한 마원으로 변화시킨다. 진마가 수행을 증가시키는 필수 단약.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["item_desc_300025"] = {  key = "item_desc_300025",  scn = "以精血炼制，掠夺生机以壮大己身，是血魔增加修为的必备丹药。",  tcn = "以精血煉製，掠奪生機以壯大己身，是血魔增加修為的必備丹藥。",  en = "Refined from vital blood, it plunders life force to strengthen oneself. An essential pill for Blood Demons to increase cultivation.",  ru = "Изготовлена из жизненной крови, похищает жизненную силу для укрепления себя. Незаменимая пилюля для увеличения культивации Кровавого Демона.",  jp = "精血を以て錬成し、生機を掠め奪い己が身を壮大きくす。血魔が修為を増やすための必須丹薬。",  kr = "정혈로 제련하여 생기를 약탈해 자신을 강화한다. 혈마가 수행을 증가시키는 필수 단약.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["item_desc_300031"] = {  key = "item_desc_300031",  scn = "滋养魂火，壮大神识，是天魔增加修为的必备丹药。",  tcn = "滋養魂火，壯大神識，是天魔增加修為的必備丹藥。",  en = "Nourishes the soul fire and expands spiritual perception. An essential pill for Heavenly Demons to increase cultivation.",  ru = "Питает огонь души и расширяет духовное восприятие. Незаменимая пилюля для увеличения культивации Небесного Демона.",  jp = "魂火を滋養し、神識を壮大にする。天魔が修為を増やすための必須丹薬。",  kr = "혼화를 자양하고 신식을 확장한다. 천마가 수행을 증가시키는 필수 단약.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["item_desc_300100"] = {  key = "item_desc_300100",  scn = "突破时服用，能瞬间汇聚海量天地灵气，助法修增加突破概率，如果突破失败，可用于修复道伤。",  tcn = "突破時服用，能瞬間匯聚海量天地靈氣，助法修增加突破概率，如果突破失敗，可用於修復道傷。",  en = "Taking during a breakthrough instantly gathers vast amounts of spiritual energy, helping Spell Cultivators increase breakthrough chance. If breakthrough fails, it can be used to repair Dao injuries.",  ru = "Приём во время прорыва мгновенно собирает огромное количество духовной энергии, помогая магу увеличить шанс прорыва. В случае неудачи может быть использовано для восстановления травм Дао.",  jp = "突破時に服用すると、瞬時に海量の天地霊気が集まり、法修の突破確率を高める。突破に失敗した場合、道傷の修復に使える。",  kr = "돌파 시 복용하면 순간적으로 방대한 천지 영기가 모여 법수의 돌파 확률을 높인다. 돌파 실패 시 도상 복구에 사용 가능.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["item_desc_300106"] = {  key = "item_desc_300106",  scn = "突破时服用，能引动体内气血极致压缩与蜕变，助体修增加突破概率，如果突破失败，可用于修复道伤。",  tcn = "突破時服用，能引動體內氣血極致壓縮與蛻變，助體修增加突破概率，如果突破失敗，可用於修復道傷。",  en = "Taking during a breakthrough triggers extreme compression and transformation of internal vitality, helping Body Cultivators increase breakthrough chance. If breakthrough fails, it can be used to repair Dao injuries.",  ru = "Приём во время прорыва вызывает экстремальное сжатие и трансформацию внутренней жизненной силы, помогая телу увеличить шанс прорыва. В случае неудачи может быть использовано для восстановления травм Дао.",  jp = "突破時に服用すると、体内の気血が極限まで圧縮・変革し、体修の突破確率を高める。突破に失敗した場合、道傷の修復に使える。",  kr = "돌파 시 복용하면 체내 기혈이 극한으로 압축되고 변혁하여 체수의 돌파 확률을 높인다. 돌파 실패 시 도상 복구에 사용 가능.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["item_desc_300112"] = {  key = "item_desc_300112",  scn = "突破时服用，使心神如剑，一往无前，助剑修增加突破概率，如果突破失败，可用于修复道伤。",  tcn = "突破時服用，使心神如劍，一往無前，助劍修增加突破概率，如果突破失敗，可用於修復道傷。",  en = "Taking during a breakthrough makes the mind and spirit like a sword, charging forward without hesitation, helping Sword Cultivators increase breakthrough chance. If breakthrough fails, it can be used to repair Dao injuries.",  ru = "Приём во время прорыва делает разум и дух подобными мечу, устремлённому вперёд без колебаний, помогая мечнику увеличить шанс прорыва. В случае неудачи может быть использовано для восстановления травм Дао.",  jp = "突破時に服用すると、心神を剣の如く一往前にさせ、剣修の突破確率を高める。突破に失敗した場合、道傷の修復に使える。",  kr = "돌파 시 복용하면 심신이 검과 같이 되어 배수진을 치게 하여 검수의 돌파 확률을 높인다. 돌파 실패 시 도상 복구에 사용 가능.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["item_desc_300118"] = {  key = "item_desc_300118",  scn = "突破时服用，蕴含狂暴魔元，强行拓宽魔脉，助真魔增加突破概率，如果突破失败，可用于修复道伤。",  tcn = "突破時服用，蘊含狂暴魔元，強行拓寬魔脈，助真魔增加突破概率，如果突破失敗，可用於修復道傷。",  en = "Taking during a breakthrough contains fierce demonic essence, forcibly expanding demon meridians, helping True Demons increase breakthrough chance. If breakthrough fails, it can be used to repair Dao injuries.",  ru = "Приём во время прорыва содержит яростную демоническую сущность, принудительно расширяя демонические меридианы, помогая Истинному Демону увеличить шанс прорыва. В случае неудачи может быть использовано для восстановления травм Дао.",  jp = "突破時に服用すると、狂暴な魔元を含み、強制的に魔脈を広げ、真魔の突破確率を高める。突破に失敗した場合、道傷の修復に使える。",  kr = "돌파 시 복용하면 광폭한 마원을 함유하여 강제로 맥맥을 확장시키고 진마의 돌파 확률을 높인다. 돌파 실패 시 도상 복구에 사용 가능.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["item_desc_300124"] = {  key = "item_desc_300124",  scn = "突破时服用，能锁住血气，让血脉翻腾，助血魔增加突破概率，如果突破失败，可用于修复道伤。",  tcn = "突破時服用，能鎖住血氣，讓血脈翻騰，助血魔增加突破概率，如果突破失敗，可用於修復道傷。",  en = "Taking during a breakthrough locks in blood energy, causing bloodlines to surge, helping Blood Demons increase breakthrough chance. If breakthrough fails, it can be used to repair Dao injuries.",  ru = "Приём во время прорыва запирает энергию крови, вызывая бурление крови, помогая Кровавому Демону увеличить шанс прорыва. В случае неудачи может быть использовано для восстановления травм Дао.",  jp = "突破時に服用すると、血気を閉じ込め、血脈を沸騰させ、血魔の突破確率を高める。突破に失敗した場合、道傷の修復に使える。",  kr = "돌파 시 복용하면 혈기를 잠그고 혈맥을 끓어오르게 하여 혈마의 돌파 확률을 높인다. 돌파 실패 시 도상 복구에 사용 가능.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["item_desc_300130"] = {  key = "item_desc_300130",  scn = "突破时服用，能淬炼神魂，更加凝实坚韧，助天魔增加突破概率，如果突破失败，可用于修复道伤。",  tcn = "突破時服用，能淬煉神魂，更加凝實堅韌，助天魔增加突破概率，如果突破失敗，可用於修復道傷。",  en = "Taking during a breakthrough tempers the soul, making it more condensed and resilient, helping Heavenly Demons increase breakthrough chance. If breakthrough fails, it can be used to repair Dao injuries.",  ru = "Приём во время прорыва закаляет душу, делая её более плотной и устойчивой, помогая Небесному Демону увеличить шанс прорыва. В случае неудачи может быть использовано для восстановления травм Дао.",  jp = "突破時に服用すると、神魂を淬煉し、より凝実で強靭にし、天魔の突破確率を高める。突破に失敗した場合、道傷の修復に使える。",  kr = "돌파 시 복용하면 신혼을 단련하여 더욱 응집되고 강인하게 하여 천마의 돌파 확률을 높인다. 돌파 실패 시 도상 복구에 사용 가능.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["item_desc_300200"] = {  key = "item_desc_300200",  scn = "在世界战斗时自动服用，恢复自身气血。恢复量为最大气血的30%，并额外恢复50气血。（血条后葫芦图标，可设置触发恢复百分比）",  tcn = "在世界戰鬥時自動服用，恢復自身氣血。恢復量為最大氣血的30%，並額外恢復50氣血。（血條後葫蘆圖示，可設置觸發恢復百分比）",  en = "Automatically taken during world combat to restore Health. Restores 30% of Max Health plus an additional 50 Health. (Gourd icon after health bar allows setting the trigger percentage)",  ru = "Автоматически принимается во время боя в мире для восстановления здоровья. Восстанавливает 30% от максимального здоровья плюс дополнительные 50 единиц здоровья. (Значок тыквы после полоски здоровья позволяет установить процент срабатывания)",  jp = "世界での戦闘時に自動服用し、自身の気血を回復する。最大気血の30%に加え、さらに50の気血を回復する。（体力ゲージ横の瓢箪アイコンで発動率を設定可能）",  kr = "세계 전투 시 자동 복용하여 자신의 기혈을 회복합니다. 최대 기혈의 30%만큼 회복하고, 추가로 50의 기혈을 회복합니다. (체력바 뒤 호리병박 아이콘으로 발동 비율 설정 가능)",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
