data["item_desc_500000"] = {  key = "item_desc_500000",  scn = "采自天外陨星，砂砾微芒中暗藏星辰之力，练气期升级洞府的主要材料。",  tcn = "採自天外隕星，砂礫微芒中暗藏星辰之力，練氣期升級洞府的主要材料。",  en = "Harvested from fallen stars beyond the heavens; within the faint glimmer of the sand grains lies hidden the power of constellations. Main material for upgrading the Abode during the Qi Refining stage.",  ru = "Добыто из упавших звёзд за пределами небес; в слабом мерцании песчинок скрыта сила созвездий. Основной материал для улучшения Обители на стадии Закаливания Ци.",  jp = "天外の隕星から採れ、砂礫の微かな輝きに星辰の力を秘める。練気期の洞府アップグレードの主材料。",  kr = "천외의 운석에서 채취하며, 모래 알갱이의 미광에 성신의 힘이 숨겨져 있다. 연하기 동부 업그레이드의 주요 재료.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
