data["item_desc_600000"] = {  key = "item_desc_600000",  scn = "以地心焰火凝炼而成，引天地灵力化作护体光罩，可挡万法侵袭。",  tcn = "以地心焰火凝煉而成，引天地靈力化作護體光罩，可擋萬法侵襲。",  en = "Refined from the flames of the earth\'s core, it channels the spiritual power of heaven and earth into a protective light shield, capable of blocking all magical attacks.",  ru = "Выковано из пламени ядра земли, направляет духовную силу неба и земли в защитный световой купол, способный блокировать все магические атаки.",  jp = "地心の焰火を以て凝煉し、天地の霊力を引き護體の光罩と化す。萬法の侵襲を防ぐべし。",  kr = "지심의 염화로 응결 제련하여 천지 영력을 끌어들여 호신 광조로 만든다. 만법의 침습을 막아낸다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["item_desc_600006"] = {  key = "item_desc_600006",  scn = "甲胄融入气血之力，穿戴后筋骨如铁，硬撼凶兽而不惧。",  tcn = "甲胄融入氣血之力，穿戴後筋骨如鐵，硬撼兇獸而不懼。",  en = "The armor integrates the power of vitality; when worn, sinews and bones become like iron, unafraid to clash with fierce beasts.",  ru = "Броня вбирает силу жизненной энергии; при ношении сухожилия и кости становятся подобны железу, не боясь столкновения со свирепыми зверями.",  jp = "甲冑に気血の力を融け込み、身に着ければ筋骨は鉄の如く、凶獣と激しくぶつかっても恐れず。",  kr = "갑주에 기혈의 힘을 융합하여 착용하면 근골이 쇠와 같이 되어 흉수와 맞서 싸워도 두렵지 않다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["item_desc_600500"] = {  key = "item_desc_600500",  scn = "剑身蕴含精纯元灵之气，锋利无比。",  tcn = "劍身蘊含精純元靈之氣，鋒利無比。",  en = "The sword blade contains pure primordial spirit energy, incomparably sharp.",  ru = "Клинок меча содержит чистую энергию изначального духа, несравненно острый.",  jp = "剣身に精純な元靈の気をたたえ、比類なき鋭さ。",  kr = "검신에 정순한 원령의 기를 담고 있어 비할 데 없이 예리하다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
data["item_desc_600506"] = {  key = "item_desc_600506",  scn = "以妖兽精血反复淬炼，枪身猩红，气血灌注可洞穿一切。",  tcn = "以妖獸精血反覆淬煉，槍身猩紅，氣血灌注可洞穿一切。",  en = "Repeatedly tempered with the vital blood of demon beasts, the spear shaft is crimson; infused with vitality, it can pierce through anything.",  ru = "Многократно закалено жизненной кровью демонических зверей, древко копья багрово; наполненное жизненной силой, может пронзить всё.",  jp = "妖兽の精血を以て反復淬煉し、槍身は真紅。気血を込めれば一切を貫く。",  kr = "요수의 정혈로 반복 단련하여 창신은 시뻘겋다. 기혈을 주입하면 모든 것을 꿰뚫는다.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
