data["item_desc_71010"] = {  key = "item_desc_71010",  scn = "冰魄为魂，绽于极寒之境，是筑基期修为丹的灵药种子。",  tcn = "冰魄為魂，綻於極寒之境，是筑基期修為丹的靈藥種子。",  en = "Ice soul as its spirit, blooming in extreme cold. Spiritual herb seeds for Foundation Establishment stage cultivation pills.",  ru = "Ледяная душа как дух, цветёт в экстремальном холоде. Семена духовных трав для пилюль культивации стадии Закладки Основы.",  jp = "氷魄を魂とし、極寒の地に咲く。築基期の修為丹の霊薬の種。",  kr = "빙백을 혼으로 하여 극한의 땅에 핀다. 주하기 수행단의 영약 씨앗.",  es = "",  pt = "",  de = "",  fr = "",  pl = "" }
